{
  "name": "ZenCanvas",
  "description": "A minimalist, distraction-free blank page for focused writing and AI-assisted ideation. Powered by Gemini, it helps you transform your thoughts into polished drafts."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Document {
  id: string;
  title: string;
  content: string;
  lastModified: number;
}

export type AIAction = 'expand' | 'summarize' | 'polish' | 'brainstorm' | 'continue';

export interface AIResponse {
  text: string;
  error?: string;
}

import { GoogleGenAI } from "@google/genai";
import { AIAction } from "../types";

export const performAIAction = async (content: string, action: AIAction): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompts: Record<AIAction, string> = {
    expand: "Expand upon the following thoughts, providing more detail and depth while maintaining the original tone:",
    summarize: "Summarize the following text concisely, capturing the core message:",
    polish: "Rewrite and polish the following text for clarity, flow, and professional tone without changing the meaning:",
    brainstorm: "Based on the following context, list 5 creative ideas or next steps for this project:",
    continue: "Continue writing the next few sentences naturally based on the current context:"
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `${prompts[action]}\n\n--- CONTENT ---\n${content}\n--- END CONTENT ---`,
      config: {
        temperature: 0.7,
        topP: 0.8,
        topK: 40,
      }
    });

    return response.text || "No response from AI.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to process your request. Please try again later.");
  }
};

import React, { useEffect, useRef } from 'react';

interface EditorProps {
  content: string;
  onChange: (content: string) => void;
  placeholder?: string;
  autoFocus?: boolean;
}

const Editor: React.FC<EditorProps> = ({ content, onChange, placeholder, autoFocus }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    if (autoFocus && textareaRef.current) {
      textareaRef.current.focus();
    }
  }, [autoFocus]);

  // Adjust height automatically based on content
  const handleInput = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const target = e.target;
    target.style.height = 'inherit';
    target.style.height = `${target.scrollHeight}px`;
    onChange(target.value);
  };

  return (
    <div className="max-w-3xl mx-auto w-full px-6 md:px-0 py-24">
      <textarea
        ref={textareaRef}
        value={content}
        onChange={handleInput}
        placeholder={placeholder || "Start writing your thoughts here..."}
        className="w-full min-h-[500px] bg-transparent border-none focus:ring-0 resize-none writing-area text-xl md:text-2xl outline-none placeholder:text-slate-300 transition-all duration-300"
        style={{ height: 'auto' }}
      />
    </div>
  );
};

export default Editor;

import React from 'react';
import { AIAction } from '../types';

interface ToolbarProps {
  onAction: (action: AIAction) => void;
  isProcessing: boolean;
  onClear: () => void;
  hasContent: boolean;
}

const Toolbar: React.FC<ToolbarProps> = ({ onAction, isProcessing, onClear, hasContent }) => {
  return (
    <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-50 transition-all duration-500">
      <div className="bg-white/80 backdrop-blur-md border border-slate-200 shadow-xl rounded-full px-2 py-2 flex items-center gap-1">

        <button
          onClick={() => onAction('polish')}
          disabled={isProcessing || !hasContent}
          className="px-4 py-2 text-sm font-medium text-slate-600 hover:text-indigo-600 hover:bg-slate-50 rounded-full transition-colors disabled:opacity-30 flex items-center gap-2"
        >
          {isProcessing ? 'Thinking...' : '✨ Polish'}
        </button>

        <div className="w-[1px] h-6 bg-slate-200 mx-1"></div>

        <button
          onClick={() => onAction('continue')}
          disabled={isProcessing || !hasContent}
          className="px-4 py-2 text-sm font-medium text-slate-600 hover:text-indigo-600 hover:bg-slate-50 rounded-full transition-colors disabled:opacity-30"
        >
          Continue
        </button>

        <button
          onClick={() => onAction('expand')}
          disabled={isProcessing || !hasContent}
          className="px-4 py-2 text-sm font-medium text-slate-600 hover:text-indigo-600 hover:bg-slate-50 rounded-full transition-colors disabled:opacity-30"
        >
          Expand
        </button>

        <div className="w-[1px] h-6 bg-slate-200 mx-1"></div>

        <button
          onClick={onClear}
          className="w-10 h-10 flex items-center justify-center text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors"
          title="Clear Canvas"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
          </svg>
        </button>
      </div>
    </div>
  );
};

export default Toolbar;

import React, { useState, useEffect, useCallback } from 'react';
import Editor from './components/Editor';
import Toolbar from './components/Toolbar';
import { performAIAction } from './services/geminiService';
import { AIAction } from './types';

const App: React.FC = () => {
  const [content, setContent] = useState<string>(() => {
    return localStorage.getItem('zencanvas_content') || '';
  });
  const [isProcessing, setIsProcessing] = useState(false);
  const [notification, setNotification] = useState<{message: string, type: 'info' | 'error'} | null>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem('zencanvas_content', content);
  }, [content]);

  // Notification cleanup
  useEffect(() => {
    if (notification) {
      const timer = setTimeout(() => setNotification(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [notification]);

  const handleAIAction = async (action: AIAction) => {
    if (!content.trim()) return;

    setIsProcessing(true);
    try {
      const result = await performAIAction(content, action);

      if (action === 'continue') {
        setContent(prev => `${prev}\n\n${result}`);
      } else {
        // For polish/summarize, we might want to replace or show a side-by-side
        // but for a "blank page" feel, we append the suggestion for selection
        setContent(prev => `${prev}\n\n--- AI SUGGESTION ---\n${result}`);
        setNotification({ message: 'Added AI suggestion to the end.', type: 'info' });
      }
    } catch (error: any) {
      setNotification({ message: error.message, type: 'error' });
    } finally {
      setIsProcessing(false);
    }
  };

  const handleClear = useCallback(() => {
    if (window.confirm("Are you sure you want to clear your canvas? This cannot be undone.")) {
      setContent('');
      localStorage.removeItem('zencanvas_content');
    }
  }, []);

  return (
    <div className="min-h-screen relative overflow-x-hidden bg-[#fafafa]">
      {/* Subtle background decoration */}
      <div className="fixed top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 opacity-20"></div>

      <header className="fixed top-0 left-0 w-full p-6 flex justify-between items-center z-40 bg-white/50 backdrop-blur-sm">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white font-bold text-xs">ZC</div>
          <h1 className="text-slate-400 font-light tracking-widest text-sm uppercase">ZenCanvas</h1>
        </div>
        <div className="text-slate-400 text-xs font-medium">
          {content.trim().split(/\s+/).filter(Boolean).length} words
        </div>
      </header>

      <main className="relative z-10">
        <Editor 
          content={content} 
          onChange={setContent} 
          autoFocus={true} 
        />
      </main>

      <Toolbar 
        onAction={handleAIAction} 
        isProcessing={isProcessing} 
        onClear={handleClear}
        hasContent={content.trim().length > 0}
      />

      {/* Notifications */}
      {notification && (
        <div className={`fixed top-20 right-6 px-6 py-3 rounded-lg shadow-lg z-50 transform transition-all duration-300 animate-bounce-short ${
          notification.type === 'error' ? 'bg-red-500 text-white' : 'bg-slate-800 text-white'
        }`}>
          {notification.message}
        </div>
      )}

      {/* Empty State Overlay */}
      {!content && !isProcessing && (
        <div className="fixed inset-0 flex items-center justify-center pointer-events-none opacity-20 select-none">
          <div className="text-center">
            <h2 className="text-6xl font-thin tracking-tighter text-slate-300">Tabula Rasa</h2>
            <p className="mt-4 text-slate-400 font-light italic">The canvas is yours.</p>
          </div>
        </div>
      )}

      <style>{`
        @keyframes bounce-short {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-5px); }
        }
        .animate-bounce-short {
          animation: bounce-short 0.5s ease-in-out;
        }
      `}</style>
    </div>
  );
};

export default App;

export interface GeneratedPage {
  id: string;
  name: string;
  html: string;
  createdAt: number;
  parentId?: string;
}

export enum GenerationState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

export interface Template {
  id: string;
  name: string;
  icon: string;
  prompt: string;
  description: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { generateWebPage, redefineWebPage } from './services/geminiService';
import { GenerationState, GeneratedPage, Template } from './types';

const TEMPLATES: Template[] = [
  {
    id: 'portfolio',
    name: 'Professional Portfolio',
    icon: 'fa-user-tie',
    description: 'Modern portfolio for designers or developers.',
    prompt: 'Create a professional, minimalist portfolio website for a Senior UX Designer. Include a hero section with a headshot placeholder, a project grid (4 items), an about section, and a contact form. Use a clean white/gray/black color palette with subtle indigo accents.'
  },
  {
    id: 'blog',
    name: 'Tech Blog Post',
    icon: 'fa-newspaper',
    description: 'Clean reading experience for articles.',
    prompt: 'Generate a beautiful, typography-focused tech blog post template. It should have a readable single-column layout, a sticky header, a progress bar for reading depth, and an author bio at the bottom. Use dark mode by default with high-contrast text.'
  },
  {
    id: 'ecommerce',
    name: 'Product Page',
    icon: 'fa-shopping-cart',
    description: 'High-converting product landing page.',
    prompt: 'Design a high-conversion e-commerce product landing page for a pair of premium wireless headphones. Include an image gallery, pricing with a prominent "Buy Now" button, a features grid with icons, and a customer reviews section. Use vibrant colors and modern shadows.'
  },
  {
    id: 'saas',
    name: 'SaaS Landing',
    icon: 'fa-rocket',
    description: 'Waitlist page for new software.',
    prompt: 'Build a minimalist SaaS waitlist landing page. Features: Catchy headline, subheadline, email signup form with a "Join Waitlist" button, and 3 key value proposition icons below. Use a soft pastel background gradient.'
  },
  {
    id: 'restaurant',
    name: 'Restaurant Menu',
    icon: 'fa-utensils',
    description: 'Elegant digital menu for dining.',
    prompt: 'Create an elegant, mobile-friendly digital menu for a high-end Italian restaurant. Categorize by Appetizers, Pasta, and Desserts. Include placeholders for food images and price tags. Use a sophisticated serif font and a cream/gold color scheme.'
  }
];

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [redefinePrompt, setRedefinePrompt] = useState('');
  const [status, setStatus] = useState<GenerationState>(GenerationState.IDLE);
  const [error, setError] = useState<string | null>(null);
  const [currentCode, setCurrentCode] = useState<string>('');
  const [activeId, setActiveId] = useState<string | null>(null);
  const [history, setHistory] = useState<GeneratedPage[]>([]);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [previewSize, setPreviewSize] = useState<'desktop' | 'mobile'>('desktop');
  const [isRedefineOpen, setIsRedefineOpen] = useState(false);

  const iframeRef = useRef<HTMLIFrameElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);

  // Update iframe content when code changes
  useEffect(() => {
    if (viewMode === 'preview' && iframeRef.current && currentCode) {
      const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
      if (doc) {
        doc.open();
        doc.write(currentCode);
        doc.close();
      }
    }
  }, [currentCode, viewMode, previewSize]);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    setStatus(GenerationState.LOADING);
    setError(null);

    try {
      const code = await generateWebPage(prompt);
      setCurrentCode(code);

      const newPage: GeneratedPage = {
        id: Date.now().toString(),
        name: prompt.substring(0, 30) + (prompt.length > 30 ? '...' : ''),
        html: code,
        createdAt: Date.now(),
      };

      setHistory(prev => [newPage, ...prev]);
      setActiveId(newPage.id);
      setStatus(GenerationState.SUCCESS);
    } catch (err: any) {
      setStatus(GenerationState.ERROR);
      setError(err.message || 'Ralat tidak dijangka berlaku.');
    }
  };

  const handleRedefine = async () => {
    if (!redefinePrompt.trim() || !currentCode || !activeId) return;

    setStatus(GenerationState.LOADING);
    setError(null);

    try {
      const updatedCode = await redefineWebPage(currentCode, redefinePrompt);
      setCurrentCode(updatedCode);

      const newId = Date.now().toString();
      const newPage: GeneratedPage = {
        id: newId,
        name: `Ubah: ${redefinePrompt.substring(0, 20)}...`,
        html: updatedCode,
        createdAt: Date.now(),
        parentId: activeId,
      };

      setHistory(prev => [newPage, ...prev]);
      setActiveId(newId);
      setRedefinePrompt('');
      setIsRedefineOpen(false);
      setStatus(GenerationState.SUCCESS);
    } catch (err: any) {
      setStatus(GenerationState.ERROR);
      setError(err.message || 'Ralat semasa mengemaskini.');
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(currentCode);
    alert('Kod disalin ke papan klip!');
  };

  const downloadFile = () => {
    const blob = new Blob([currentCode], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'index.html';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const toggleFullScreen = () => {
    if (previewContainerRef.current) {
      if (!document.fullscreenElement) {
        previewContainerRef.current.requestFullscreen().catch(err => {
          alert(`Error attempting to enable full-screen mode: ${err.message} (${err.name})`);
        });
      } else {
        document.exitFullscreen();
      }
    }
  };

  const selectFromHistory = (page: GeneratedPage) => {
    setCurrentCode(page.html);
    setActiveId(page.id);
    setIsRedefineOpen(false);
  };

  const selectTemplate = (t: Template) => {
    setPrompt(t.prompt);
    // Smoothly scroll to textarea for feedback
    const textarea = document.getElementById('generation-input');
    textarea?.focus();
  };

  // Tree Rendering Logic
  const renderHistoryItem = (page: GeneratedPage, depth: number = 0) => {
    const children = history.filter(item => item.parentId === page.id);
    const isActive = activeId === page.id;

    return (
      <div key={page.id} className="flex flex-col">
        <button
          onClick={() => selectFromHistory(page)}
          className={`w-full text-left p-2 rounded-lg border transition-all text-xs flex justify-between items-center group mb-1 ${
            isActive 
              ? 'border-indigo-600 bg-indigo-50 text-indigo-700' 
              : 'border-slate-100 hover:bg-slate-50 text-slate-600'
          }`}
          style={{ marginLeft: `${depth * 16}px` }}
        >
          <div className="flex items-center gap-2 truncate">
            {depth > 0 && <i className="fa-solid fa-turn-up rotate-90 text-[10px] text-slate-300"></i>}
            <span className="truncate pr-1 font-medium">{page.name}</span>
          </div>
          <i className={`fa-solid fa-chevron-right text-[10px] transition-transform ${isActive ? 'translate-x-1' : ''}`}></i>
        </button>
        {children.length > 0 && (
          <div className="border-l border-slate-100 ml-2">
            {children.map(child => renderHistoryItem(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };

  const rootHistory = history.filter(item => !item.parentId);

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-white border-b px-6 py-4 flex items-center justify-between sticky top-0 z-50 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <i className="fa-solid fa-wand-magic-sparkles text-white text-xl"></i>
          </div>
          <h1 className="text-xl font-bold bg-gradient-to-r from-indigo-600 to-violet-600 bg-clip-text text-transparent">
            InstaPage AI
          </h1>
        </div>

        <div className="hidden md:flex items-center gap-4">
          <span className="text-xs font-bold text-slate-400 uppercase tracking-widest mr-2">Quick Start:</span>
          {TEMPLATES.slice(0, 3).map(t => (
            <button 
              key={t.id}
              onClick={() => selectTemplate(t)}
              className="text-xs bg-slate-50 border border-slate-200 px-3 py-1.5 rounded-full text-slate-600 hover:text-indigo-600 hover:border-indigo-600 transition-all font-medium"
            >
              {t.name}
            </button>
          ))}
        </div>
      </header>

      <main className="flex-1 flex flex-col md:flex-row h-[calc(100vh-73px)] overflow-hidden">
        {/* Sidebar Controls */}
        <aside className="w-full md:w-[400px] bg-white border-r flex flex-col overflow-y-auto p-6 space-y-6">
          <div className="space-y-4">
            <div>
              <div className="flex items-center justify-between mb-2">
                <label className="block text-sm font-semibold text-slate-700">
                  Generate New Page
                </label>
                <div className="text-[10px] text-slate-400 font-bold uppercase">Templates Below ↓</div>
              </div>

              {/* Template Carousel */}
              <div className="flex gap-2 overflow-x-auto pb-4 mb-2 no-scrollbar scroll-smooth">
                {TEMPLATES.map(t => (
                  <button
                    key={t.id}
                    onClick={() => selectTemplate(t)}
                    className="flex-shrink-0 w-28 p-3 bg-slate-50 border border-slate-100 rounded-xl hover:border-indigo-400 transition-all text-center group"
                  >
                    <div className="w-8 h-8 mx-auto mb-2 bg-white rounded-lg flex items-center justify-center text-indigo-600 group-hover:scale-110 transition-transform shadow-sm">
                      <i className={`fa-solid ${t.icon} text-sm`}></i>
                    </div>
                    <span className="text-[10px] font-bold text-slate-600 uppercase block leading-tight">{t.name}</span>
                  </button>
                ))}
              </div>

              <textarea
                id="generation-input"
                className="w-full h-32 p-3 border rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 resize-none transition-all outline-none bg-slate-50 text-sm shadow-inner"
                placeholder="Describe what you want to build... (or choose a template above)"
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
              />
              <button
                onClick={handleGenerate}
                disabled={status === GenerationState.LOADING || !prompt.trim()}
                className={`w-full mt-2 py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all text-sm shadow-lg ${
                  status === GenerationState.LOADING 
                    ? 'bg-slate-200 text-slate-500 cursor-not-allowed' 
                    : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-indigo-100'
                }`}
              >
                {status === GenerationState.LOADING && !isRedefineOpen ? (
                  <i className="fa-solid fa-circle-notch animate-spin"></i>
                ) : (
                  <i className="fa-solid fa-sparkles"></i>
                )}
                Generate Page
              </button>
            </div>

            {currentCode && (
              <div className={`p-4 rounded-xl border-2 transition-all ${isRedefineOpen ? 'border-indigo-500 bg-indigo-50' : 'border-slate-100 bg-slate-50'}`}>
                <div className="flex items-center justify-between mb-2">
                  <label className="block text-sm font-bold text-slate-700">
                    Refine Current Page
                  </label>
                  {!isRedefineOpen && (
                    <button 
                      onClick={() => setIsRedefineOpen(true)}
                      className="text-xs text-indigo-600 font-semibold hover:underline"
                    >
                      Open Edit
                    </button>
                  )}
                </div>

                {isRedefineOpen ? (
                  <div className="space-y-3">
                    <textarea
                      className="w-full h-24 p-3 border border-indigo-200 rounded-lg focus:ring-2 focus:ring-indigo-500 resize-none transition-all outline-none bg-white text-sm"
                      placeholder="What would you like to change? (e.g. 'Make the buttons larger', 'Add a dark footer')"
                      value={redefinePrompt}
                      onChange={(e) => setRedefinePrompt(e.target.value)}
                      autoFocus
                    />
                    <div className="flex gap-2">
                      <button
                        onClick={handleRedefine}
                        disabled={status === GenerationState.LOADING || !redefinePrompt.trim()}
                        className="flex-1 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold hover:bg-indigo-700 transition-all flex items-center justify-center gap-2"
                      >
                        {status === GenerationState.LOADING && isRedefineOpen ? <i className="fa-solid fa-circle-notch animate-spin"></i> : <i className="fa-solid fa-wand-sparkles"></i>}
                        Apply Changes
                      </button>
                      <button
                        onClick={() => { setIsRedefineOpen(false); setRedefinePrompt(''); }}
                        className="px-3 py-2 bg-white border text-slate-500 rounded-lg text-sm hover:bg-slate-50"
                      >
                        Cancel
                      </button>
                    </div>
                  </div>
                ) : (
                  <p className="text-xs text-slate-500 italic">Use this to add features or tweak the design of the visible page.</p>
                )}
              </div>
            )}
          </div>

          {error && (
            <div className="p-4 bg-red-50 border border-red-100 rounded-xl text-red-600 text-sm flex items-start gap-3">
              <i className="fa-solid fa-triangle-exclamation mt-1"></i>
              <p>{error}</p>
            </div>
          )}

          {/* History */}
          <div className="flex-1 flex flex-col min-h-0">
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-3 flex items-center justify-between">
              <span>Versions & History</span>
              <span className="text-[10px] bg-slate-100 px-2 py-0.5 rounded-full">{history.length}</span>
            </h3>
            <div className="flex-1 overflow-y-auto space-y-4 pr-1 scrollbar-thin">
              {rootHistory.length === 0 ? (
                <div className="text-center py-8 text-slate-400 italic text-sm border border-dashed border-slate-200 rounded-xl">
                  No pages generated yet.
                </div>
              ) : (
                rootHistory.map(rootPage => renderHistoryItem(rootPage))
              )}
            </div>
          </div>

          <div className="pt-4 border-t text-[10px] text-slate-400 text-center uppercase tracking-widest font-bold">
            Powered by Gemini 3 Flash
          </div>
        </aside>

        {/* Preview / Code Area */}
        <section className="flex-1 bg-slate-100 p-4 flex flex-col overflow-hidden">
          <div className="bg-white rounded-t-xl border-x border-t p-2 flex flex-wrap items-center justify-between shadow-sm gap-y-2">
            <div className="flex items-center gap-2">
              <button
                onClick={() => setViewMode('preview')}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${
                  viewMode === 'preview' ? 'bg-indigo-100 text-indigo-700' : 'text-slate-500 hover:bg-slate-50'
                }`}
              >
                <i className="fa-solid fa-eye mr-2"></i>
                Preview
              </button>
              <button
                onClick={() => setViewMode('code')}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${
                  viewMode === 'code' ? 'bg-indigo-100 text-indigo-700' : 'text-slate-500 hover:bg-slate-50'
                }`}
              >
                <i className="fa-solid fa-code mr-2"></i>
                Source Code
              </button>
            </div>

            {viewMode === 'preview' && currentCode && (
              <div className="flex items-center bg-slate-100 rounded-lg p-1 mr-auto ml-2">
                <button
                  onClick={() => setPreviewSize('desktop')}
                  className={`p-1.5 rounded-md text-sm transition-all ${previewSize === 'desktop' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                  title="Desktop View"
                >
                  <i className="fa-solid fa-desktop"></i>
                </button>
                <button
                  onClick={() => setPreviewSize('mobile')}
                  className={`p-1.5 rounded-md text-sm transition-all ${previewSize === 'mobile' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                  title="Mobile View"
                >
                  <i className="fa-solid fa-mobile-screen"></i>
                </button>
              </div>
            )}

            {currentCode && (
              <div className="flex items-center gap-2">
                {viewMode === 'preview' && (
                  <button
                    onClick={toggleFullScreen}
                    className="p-2 text-slate-500 hover:text-indigo-600 transition-colors"
                    title="Full Screen Preview"
                  >
                    <i className="fa-solid fa-expand"></i>
                  </button>
                )}
                <button
                  onClick={() => setIsRedefineOpen(!isRedefineOpen)}
                  className={`px-3 py-1.5 rounded-lg text-sm font-medium flex items-center gap-2 transition-all ${isRedefineOpen ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-700 hover:bg-indigo-50 hover:text-indigo-600'}`}
                  title="Modify this page"
                >
                  <i className="fa-solid fa-pen-to-square"></i>
                  <span className="hidden sm:inline">Modify</span>
                </button>
                <button
                  onClick={copyToClipboard}
                  className="p-2 text-slate-500 hover:text-indigo-600 transition-colors"
                  title="Copy Code"
                >
                  <i className="fa-solid fa-copy"></i>
                </button>
                <button
                  onClick={downloadFile}
                  className="bg-slate-900 text-white px-4 py-1.5 rounded-lg text-sm font-medium hover:bg-slate-800 transition-all flex items-center gap-2"
                >
                  <i className="fa-solid fa-download"></i>
                  Export
                </button>
              </div>
            )}
          </div>

          <div 
            ref={previewContainerRef}
            className={`flex-1 bg-white border rounded-b-xl shadow-inner relative overflow-hidden flex flex-col items-center justify-center ${viewMode === 'preview' && previewSize === 'mobile' ? 'bg-slate-200' : 'bg-white'}`}
          >
            {!currentCode && status !== GenerationState.LOADING && (
              <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300 p-8 text-center bg-white">
                <div className="bg-slate-50 p-8 rounded-full mb-6">
                  <i className="fa-solid fa-magic-wand-sparkles text-6xl opacity-20 text-indigo-600"></i>
                </div>
                <p className="text-xl font-bold text-slate-400">Ready to build your dream page?</p>
                <p className="text-sm text-slate-400 mt-2 max-w-sm">Describe anything from a minimalist portfolio to a complex e-commerce shop, or pick one of our templates to get started instantly.</p>

                <div className="mt-8 flex flex-wrap justify-center gap-2 max-w-lg">
                   {TEMPLATES.map(t => (
                      <button 
                        key={t.id + '_landing'}
                        onClick={() => selectTemplate(t)}
                        className="px-4 py-2 border border-slate-200 rounded-full text-xs font-semibold text-slate-500 hover:bg-indigo-50 hover:text-indigo-600 hover:border-indigo-200 transition-all"
                      >
                        <i className={`fa-solid ${t.icon} mr-2`}></i>
                        {t.name}
                      </button>
                   ))}
                </div>
              </div>
            )}

            {status === GenerationState.LOADING && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/95 backdrop-blur-sm z-10">
                <div className="relative">
                  <div className="w-20 h-20 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin mb-6"></div>
                  <i className="fa-solid fa-magic-wand-sparkles absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-[60%] text-indigo-600 text-xl animate-pulse"></i>
                </div>
                <p className="text-indigo-900 font-bold text-xl tracking-tight">
                  {isRedefineOpen ? 'Refining your page...' : 'Brewing your website...'}
                </p>
                <p className="text-slate-500 text-sm mt-3 font-medium">This usually takes about 10-15 seconds.</p>
                <div className="mt-6 flex gap-1">
                  <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce" style={{animationDelay: '0s'}}></div>
                  <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce" style={{animationDelay: '0.1s'}}></div>
                  <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                </div>
              </div>
            )}

            {viewMode === 'preview' ? (
              <div 
                className={`transition-all duration-300 shadow-2xl flex flex-col ${
                  previewSize === 'mobile' 
                  ? 'w-[375px] h-[667px] max-h-full border-[12px] border-slate-800 rounded-[40px] overflow-hidden' 
                  : 'w-full h-full border-none rounded-none'
                }`}
              >
                {previewSize === 'mobile' && (
                  <div className="h-6 bg-slate-800 w-full flex justify-center items-center">
                    <div className="w-16 h-1 bg-slate-700 rounded-full"></div>
                  </div>
                )}
                <iframe
                  ref={iframeRef}
                  title="Preview"
                  className="w-full flex-1 bg-white"
                />
              </div>
            ) : (
              <pre className="w-full h-full p-6 overflow-auto bg-slate-900 text-slate-100 font-mono text-xs sm:text-sm leading-relaxed scrollbar-thin scrollbar-thumb-slate-700">
                {currentCode || '// Source code will appear here after generation...'}
              </pre>
            )}
          </div>
        </section>
      </main>

      {/* Mobile Input Container */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 p-4 bg-white border-t flex flex-col gap-2 z-[60] shadow-2xl">
        {currentCode && (
          <button 
             onClick={() => setIsRedefineOpen(!isRedefineOpen)}
             className={`w-full py-2 rounded-lg text-xs font-bold transition-all flex items-center justify-center gap-2 ${isRedefineOpen ? 'bg-indigo-600 text-white' : 'bg-indigo-50 text-indigo-700'}`}
          >
            <i className="fa-solid fa-pen-to-square"></i>
            {isRedefineOpen ? 'Close Editor' : 'Modify Current Page'}
          </button>
        )}
        <div className="flex gap-2">
          <input 
              type="text"
              className="flex-1 border rounded-lg px-4 py-3 text-sm outline-none focus:ring-1 focus:ring-indigo-500 bg-slate-50"
              placeholder={isRedefineOpen ? "Describe modification..." : "Describe new page idea..."}
              value={isRedefineOpen ? redefinePrompt : prompt}
              onChange={(e) => isRedefineOpen ? setRedefinePrompt(e.target.value) : setPrompt(e.target.value)}
          />
          <button 
              onClick={isRedefineOpen ? handleRedefine : handleGenerate}
              disabled={status === GenerationState.LOADING || (isRedefineOpen ? !redefinePrompt.trim() : !prompt.trim())}
              className="bg-indigo-600 text-white px-5 py-3 rounded-lg text-sm font-bold shadow-md"
          >
            {status === GenerationState.LOADING ? <i className="fa-solid fa-circle-notch animate-spin"></i> : <i className="fa-solid fa-paper-plane"></i>}
          </button>
        </div>
      </div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar {
          display: none;
        }
        .no-scrollbar {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
      `}</style>
    </div>
  );
};

export default App;

