  },
  {
    id: 'ecommerce',
    name: 'Product Page',
    icon: 'fa-shopping-cart',
    description: 'High-converting product landing page.',
    prompt: 'Design a high-conversion e-commerce product landing page for a pair of premium wireless headphones. Include an image gallery, pricing with a prominent "Buy Now" button, a features grid with icons, and a customer reviews section. Use vibrant colors and modern shadows.'
