import React, { useState, useEffect, useRef } from 'react';
import { generateWebPage, redefineWebPage } from './services/geminiService';
import { GenerationState, GeneratedPage } from './types';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [redefinePrompt, setRedefinePrompt] = useState('');
  const [status, setStatus] = useState<GenerationState>(GenerationState.IDLE);
  const [error, setError] = useState<string | null>(null);
  const [currentCode, setCurrentCode] = useState<string>('');
  const [activeId, setActiveId] = useState<string | null>(null);
  const [history, setHistory] = useState<GeneratedPage[]>([]);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [previewSize, setPreviewSize] = useState<'desktop' | 'mobile'>('desktop');
  const [isRedefineOpen, setIsRedefineOpen] = useState(false);

  const iframeRef = useRef<HTMLIFrameElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);

  // Update iframe content when code changes
  useEffect(() => {
    if (viewMode === 'preview' && iframeRef.current && currentCode) {
      const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
      if (doc) {
        doc.open();
        doc.write(currentCode);
        doc.close();
      }
    }
  }, [currentCode, viewMode, previewSize]);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    setStatus(GenerationState.LOADING);
    setError(null);

    try {
      const code = await generateWebPage(prompt);
      setCurrentCode(code);

      const newPage: GeneratedPage = {
        id: Date.now().toString(),
        name: prompt.substring(0, 30) + (prompt.length > 30 ? '...' : ''),
        html: code,
        createdAt: Date.now(),
      };

      setHistory(prev => [newPage, ...prev]);
      setActiveId(newPage.id);
      setStatus(GenerationState.SUCCESS);
    } catch (err: any) {
      setStatus(GenerationState.ERROR);
      setError(err.message || 'Ralat tidak dijangka berlaku.');
    }
  };

  const handleRedefine = async () => {
    if (!redefinePrompt.trim() || !currentCode || !activeId) return;

    setStatus(GenerationState.LOADING);
    setError(null);

    try {
      const updatedCode = await redefineWebPage(currentCode, redefinePrompt);
      setCurrentCode(updatedCode);

      const newId = Date.now().toString();
      const newPage: GeneratedPage = {
        id: newId,
        name: `Ubah: ${redefinePrompt.substring(0, 20)}...`,
        html: updatedCode,
        createdAt: Date.now(),
        parentId: activeId,
      };

      setHistory(prev => [newPage, ...prev]);
      setActiveId(newId);
      setRedefinePrompt('');
      setIsRedefineOpen(false);
      setStatus(GenerationState.SUCCESS);
    } catch (err: any) {
      setStatus(GenerationState.ERROR);
      setError(err.message || 'Ralat semasa mengemaskini.');
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(currentCode);
    alert('Kod disalin ke papan klip!');
  };

  const downloadFile = () => {
    const blob = new Blob([currentCode], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'index.html';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const toggleFullScreen = () => {
    if (previewContainerRef.current) {
      if (!document.fullscreenElement) {
        previewContainerRef.current.requestFullscreen().catch(err => {
          alert(`Error attempting to enable full-screen mode: ${err.message} (${err.name})`);
        });
      } else {
        document.exitFullscreen();
      }
