const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('instapage_lang') as Language) || 'en';
  });

  const [theme, setTheme] = useState<Theme>(() => {
    return (localStorage.getItem('instapage_theme') as Theme) || 'light';
  });

  const t = TRANSLATIONS[lang];

  const [prompt, setPrompt] = useState('');
  const [redefinePrompt, setRedefinePrompt] = useState('');
  const [status, setStatus] = useState<GenerationState>(GenerationState.IDLE);
  const [error, setError] = useState<string | null>(null);
  const [currentCode, setCurrentCode] = useState<string>('');
  const [activeId, setActiveId] = useState<string | null>(null);
  const [history, setHistory] = useState<GeneratedPage[]>([]);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [previewSize, setPreviewSize] = useState<'desktop' | 'mobile'>('desktop');
  const [isRedefineOpen, setIsRedefineOpen] = useState(false);

  const [templates, setTemplates] = useState<Template[]>([]);
  const [isGeneratingTemplates, setIsGeneratingTemplates] = useState(false);

  const iframeRef = useRef<HTMLIFrameElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);

  // Sync Language
  useEffect(() => {
    localStorage.setItem('instapage_lang', lang);
  }, [lang]);

  // Sync Theme with DOM and LocalStorage
  useEffect(() => {
    localStorage.setItem('instapage_theme', theme);
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  // Initial templates load
  useEffect(() => {
    refreshTemplates();
  }, [lang]);

  const refreshTemplates = async () => {
    setIsGeneratingTemplates(true);
    try {
      const suggested = await generateTemplateSuggestions(lang);
      setTemplates(suggested);
    } catch (err) {
      console.error("Failed to load templates", err);
    } finally {
      setIsGeneratingTemplates(false);
    }
  };

  useEffect(() => {
    if (viewMode === 'preview' && iframeRef.current && currentCode) {
      const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
      if (doc) {
        doc.open();
        doc.write(currentCode);
        doc.close();
      }
    }
  }, [currentCode, viewMode, previewSize]);

  const handleGenerate = async (customPrompt?: string) => {
    const finalPrompt = customPrompt || prompt;
    if (!finalPrompt.trim()) return;

    setStatus(GenerationState.LOADING);
    setError(null);

    try {
      const code = await generateWebPage(finalPrompt);
      setCurrentCode(code);

      const newPage: GeneratedPage = {
        id: Date.now().toString(),
        name: finalPrompt.substring(0, 30) + (finalPrompt.length > 30 ? '...' : ''),
        html: code,
        createdAt: Date.now(),
      };

      setHistory(prev => [newPage, ...prev]);
      setActiveId(newPage.id);
      setStatus(GenerationState.SUCCESS);
    } catch (err: any) {
      setStatus(GenerationState.ERROR);
      setError(err.message || t.genericError);
    }
  };

  const handleRedefine = async () => {
    if (!redefinePrompt.trim() || !currentCode || !activeId) return;

    setStatus(GenerationState.LOADING);
    setError(null);

    try {
      const updatedCode = await redefineWebPage(currentCode, redefinePrompt);
      setCurrentCode(updatedCode);

      const newId = Date.now().toString();
      const newPage: GeneratedPage = {
        id: newId,
        name: `${lang === 'en' ? 'Refine' : 'Ubah'}: ${redefinePrompt.substring(0, 20)}...`,
        html: updatedCode,
        createdAt: Date.now(),
        parentId: activeId,
      };

      setHistory(prev => [newPage, ...prev]);
      setActiveId(newId);
      setRedefinePrompt('');
      setIsRedefineOpen(false);
      setStatus(GenerationState.SUCCESS);
    } catch (err: any) {
      setStatus(GenerationState.ERROR);
      setError(err.message || t.genericError);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(currentCode);
    alert(t.copied);
  };

  const downloadFile = () => {
    const blob = new Blob([currentCode], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'index.html';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const toggleFullScreen = () => {
    if (previewContainerRef.current) {
      if (!document.fullscreenElement) {
        previewContainerRef.current.requestFullscreen().catch(err => {
          alert(`Error: ${err.message}`);
        });
      } else {
        document.exitFullscreen();
      }
    }
  };

  const selectFromHistory = (page: GeneratedPage) => {
    setCurrentCode(page.html);
    setActiveId(page.id);
    setIsRedefineOpen(false);
  };

  const handleTemplateClick = (temp: Template) => {
    setPrompt(temp.prompt);
    handleGenerate(temp.prompt);
  };

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const renderHistoryItem = (page: GeneratedPage, depth: number = 0) => {
    const children = history.filter(item => item.parentId === page.id);
    const isActive = activeId === page.id;

    return (
      <div key={page.id} className="flex flex-col">
        <button
          onClick={() => selectFromHistory(page)}
          className={`w-full text-left p-2 rounded-lg border transition-all text-xs flex justify-between items-center group mb-1 ${
            isActive 
              ? 'border-indigo-600 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300' 
              : 'border-slate-100 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-400'
          }`}
          style={{ marginLeft: `${depth * 16}px` }}
        >
          <div className="flex items-center gap-2 truncate">
            {depth > 0 && <i className="fa-solid fa-turn-up rotate-90 text-[10px] text-slate-300 dark:text-slate-600"></i>}
            <span className="truncate pr-1 font-medium">{page.name}</span>
          </div>
          <i className={`fa-solid fa-chevron-right text-[10px] transition-transform ${isActive ? 'translate-x-1' : ''}`}></i>
        </button>
        {children.length > 0 && (
          <div className="border-l border-slate-100 dark:border-slate-700 ml-2">
            {children.map(child => renderHistoryItem(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };

  const rootHistory = history.filter(item => !item.parentId);

  return (
    <div className="min-h-screen flex flex-col transition-colors duration-300 bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-slate-100">
      <header className="bg-white dark:bg-slate-900 border-b dark:border-slate-800 px-6 py-4 flex items-center justify-between sticky top-0 z-50 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <i className="fa-solid fa-wand-magic-sparkles text-white text-xl"></i>
          </div>
          <h1 className="text-xl font-bold bg-gradient-to-r from-indigo-600 to-violet-600 bg-clip-text text-transparent">
            InstaPage AI
          </h1>
        </div>

        <div className="flex items-center gap-3">
          {/* Theme Toggle */}
          <button 
            onClick={toggleTheme}
            className="p-2 w-10 h-10 flex items-center justify-center rounded-full bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-400 transition-all"
            title={theme === 'light' ? t.themeNight : t.themeDay}
          >
            {theme === 'light' ? <i className="fa-solid fa-moon"></i> : <i className="fa-solid fa-sun"></i>}
          </button>

          {/* Language Toggle */}
          <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 p-1 rounded-full">
            <button 
              onClick={() => setLang('en')}
              className={`px-3 py-1 text-xs font-bold rounded-full transition-all ${lang === 'en' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700'}`}
            >
              EN
            </button>
            <button 
              onClick={() => setLang('bm')}
              className={`px-3 py-1 text-xs font-bold rounded-full transition-all ${lang === 'bm' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700'}`}
            >
              BM
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 flex flex-col md:flex-row h-[calc(100vh-73px)] overflow-hidden">
        <aside className="w-full md:w-[400px] bg-white dark:bg-slate-900 border-r dark:border-slate-800 flex flex-col overflow-y-auto p-6 space-y-6 shadow-xl">
          <div className="space-y-4">
            <div>
              <div className="flex items-center justify-between mb-2">
                <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300">
                  {t.generateNew}
                </label>
              </div>
              <textarea
                id="generation-input"
                className="w-full h-40 p-3 border dark:border-slate-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 resize-none transition-all outline-none bg-slate-50 dark:bg-slate-800 text-sm shadow-inner dark:text-slate-100"
                placeholder={t.placeholderPrompt}
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
              />
              <button
                onClick={() => handleGenerate()}
                disabled={status === GenerationState.LOADING && !isRedefineOpen}
                className={`w-full mt-2 py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all text-sm shadow-lg ${
                  status === GenerationState.LOADING && !isRedefineOpen 
                    ? 'bg-slate-200 dark:bg-slate-800 text-slate-500 dark:text-slate-600 cursor-not-allowed' 
                    : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-indigo-100 dark:shadow-none'
                }`}
              >
                {status === GenerationState.LOADING && !isRedefineOpen ? (
                  <i className="fa-solid fa-circle-notch animate-spin"></i>
                ) : (
                  <i className="fa-solid fa-sparkles"></i>
                )}
                {t.generateBtn}
              </button>
            </div>

            {currentCode && (
              <div className={`p-4 rounded-xl border-2 transition-all ${isRedefineOpen ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-900/10' : 'border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/50'}`}>
                <div className="flex items-center justify-between mb-2">
                  <label className="block text-sm font-bold text-slate-700 dark:text-slate-300">
                    {t.refineTitle}
                  </label>
                  {!isRedefineOpen && (
                    <button 
                      onClick={() => setIsRedefineOpen(true)}
                      className="text-xs text-indigo-600 dark:text-indigo-400 font-semibold hover:underline"
                    >
                      {t.openEdit}
                    </button>
                  )}
                </div>
                {isRedefineOpen ? (
                  <div className="space-y-3">
                    <textarea
                      className="w-full h-24 p-3 border border-indigo-200 dark:border-indigo-900 rounded-lg focus:ring-2 focus:ring-indigo-500 resize-none transition-all outline-none bg-white dark:bg-slate-800 text-sm dark:text-slate-100"
                      placeholder={t.refinePlaceholder}
                      value={redefinePrompt}
                      onChange={(e) => setRedefinePrompt(e.target.value)}
                      autoFocus
                    />
                    <div className="flex gap-2">
                      <button
                        onClick={handleRedefine}
                        disabled={status === GenerationState.LOADING || !redefinePrompt.trim()}
                        className="flex-1 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold hover:bg-indigo-700 transition-all flex items-center justify-center gap-2"
                      >
                        {status === GenerationState.LOADING && isRedefineOpen ? <i className="fa-solid fa-circle-notch animate-spin"></i> : <i className="fa-solid fa-wand-sparkles"></i>}
                        {t.applyChanges}
                      </button>
                      <button
                        onClick={() => { setIsRedefineOpen(false); setRedefinePrompt(''); }}
                        className="px-3 py-2 bg-white dark:bg-slate-700 border dark:border-slate-600 text-slate-500 dark:text-slate-300 rounded-lg text-sm hover:bg-slate-50 dark:hover:bg-slate-600"
                      >
                        {t.cancel}
                      </button>
                    </div>
                  </div>
                ) : (
                  <p className="text-xs text-slate-500 dark:text-slate-400 italic">{t.refineTip}</p>
                )}
              </div>
            )}
          </div>

          <div className="flex-1 flex flex-col min-h-0">
            <h3 className="text-sm font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 flex items-center justify-between">
              <span>{t.historyTitle}</span>
              <span className="text-[10px] bg-slate-100 dark:bg-slate-800 px-2 py-0.5 rounded-full">{history.length}</span>
            </h3>
            <div className="flex-1 overflow-y-auto space-y-4 pr-1 scrollbar-thin">
              {rootHistory.length === 0 ? (
                <div className="text-center py-8 text-slate-400 dark:text-slate-600 italic text-sm border border-dashed border-slate-200 dark:border-slate-800 rounded-xl">
                  {t.noPages}
                </div>
              ) : (
                rootHistory.map(rootPage => renderHistoryItem(rootPage))
              )}
            </div>
          </div>
        </aside>

        <section className="flex-1 bg-slate-100 dark:bg-slate-950 p-4 flex flex-col overflow-hidden">
          <div className="bg-white dark:bg-slate-900 rounded-t-xl border-x border-t dark:border-slate-800 p-2 flex flex-wrap items-center justify-between shadow-sm gap-y-2">
            <div className="flex items-center gap-2">
              <button
                onClick={() => setViewMode('preview')}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${
                  viewMode === 'preview' ? 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-300' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'
                }`}
              >
                <i className="fa-solid fa-eye mr-2"></i>
                {t.preview}
              </button>
              <button
                onClick={() => setViewMode('code')}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${
                  viewMode === 'code' ? 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-300' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'
                }`}
              >
                <i className="fa-solid fa-code mr-2"></i>
                {t.code}
              </button>
            </div>

            {currentCode && (
              <div className="flex items-center gap-2">
                {viewMode === 'preview' && (
                  <button
                    onClick={toggleFullScreen}
                    className="p-2 text-slate-500 dark:text-slate-400 hover:text-indigo-600 transition-colors"
                    title="Full Screen Preview"
                  >
                    <i className="fa-solid fa-expand"></i>
                  </button>
                )}
                <button
                  onClick={() => setIsRedefineOpen(!isRedefineOpen)}
                  className={`px-3 py-1.5 rounded-lg text-sm font-medium flex items-center gap-2 transition-all ${isRedefineOpen ? 'bg-indigo-600 text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 hover:text-indigo-600'}`}
                >
                  <i className="fa-solid fa-pen-to-square"></i>
                  <span className="hidden sm:inline">{t.modify}</span>
                </button>
                <button
                  onClick={copyToClipboard}
                  className="p-2 text-slate-500 dark:text-slate-400 hover:text-indigo-600 transition-colors"
                  title={t.copy}
                >
                  <i className="fa-solid fa-copy"></i>
                </button>
                <button
                  onClick={downloadFile}
                  className="bg-slate-900 dark:bg-slate-100 dark:text-slate-900 text-white px-4 py-1.5 rounded-lg text-sm font-medium hover:bg-slate-800 dark:hover:bg-white transition-all flex items-center gap-2"
                >
                  <i className="fa-solid fa-download"></i>
                  {t.export}
                </button>
              </div>
            )}
          </div>

          <div 
            ref={previewContainerRef}
            className="flex-1 bg-white dark:bg-slate-900 border dark:border-slate-800 rounded-b-xl shadow-inner relative overflow-hidden flex flex-col items-center justify-center"
          >
            {!currentCode && status !== GenerationState.LOADING && (
              <div className="absolute inset-0 flex flex-col items-center justify-start text-slate-300 dark:text-slate-700 p-8 pt-16 overflow-y-auto bg-white dark:bg-slate-900">
                <div className="bg-indigo-50 dark:bg-indigo-900/20 p-6 rounded-full mb-6">
                  <i className="fa-solid fa-magic-wand-sparkles text-5xl text-indigo-600 opacity-60"></i>
                </div>
                <h2 className="text-2xl font-bold text-slate-800 dark:text-slate-100 mb-2">{t.emptyTitle}</h2>
                <p className="text-sm text-slate-500 dark:text-slate-400 mb-8 max-w-md text-center">{t.emptySubtitle}</p>
                <div className="w-full max-w-4xl">
                  <div className="flex items-center justify-between mb-4 px-2">
                    <h3 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.suggestedTemplates}</h3>
                    <button 
                      onClick={refreshTemplates}
                      disabled={isGeneratingTemplates}
                      className="text-xs font-bold text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 flex items-center gap-2 transition-colors disabled:opacity-50"
                    >
                      <i className={`fa-solid fa-rotate ${isGeneratingTemplates ? 'animate-spin' : ''}`}></i>
                      {t.refreshIdeas}
                    </button>
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    {isGeneratingTemplates ? (
                      Array(6).fill(0).map((_, i) => (
                        <div key={i} className="h-32 bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-xl animate-pulse"></div>
                      ))
                    ) : (
                      templates.map((temp) => (
                        <button
                          key={temp.id}
                          onClick={() => handleTemplateClick(temp)}
                          className="group text-left p-5 bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl hover:border-indigo-500 hover:shadow-xl hover:shadow-indigo-50/50 dark:hover:shadow-none transition-all duration-300"
                        >
                          <div className="w-10 h-10 mb-4 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl flex items-center justify-center text-indigo-600 dark:text-indigo-400 group-hover:scale-110 transition-transform">
                            <i className={`fa-solid ${temp.icon} text-lg`}></i>
                          </div>
                          <h4 className="font-bold text-slate-800 dark:text-slate-100 mb-1 group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{temp.name}</h4>
                          <p className="text-xs text-slate-500 dark:text-slate-400 line-clamp-2 leading-relaxed">{temp.description}</p>
                        </button>
                      ))
                    )}
                  </div>
                </div>
              </div>
            )}

            {status === GenerationState.LOADING && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/95 dark:bg-slate-900/95 backdrop-blur-sm z-10">
                <div className="relative">
                  <div className="w-20 h-20 border-4 border-indigo-100 dark:border-indigo-900 border-t-indigo-600 rounded-full animate-spin mb-6"></div>
                  <i className="fa-solid fa-magic-wand-sparkles absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-[60%] text-indigo-600 text-xl animate-pulse"></i>
                </div>
                <p className="text-indigo-900 dark:text-indigo-300 font-bold text-xl tracking-tight text-center">
                  {isRedefineOpen ? t.refining : t.brewing}
                </p>
                <p className="text-slate-500 dark:text-slate-400 text-sm mt-3 font-medium">{t.secondsTip}</p>
              </div>
            )}

            {viewMode === 'preview' ? (
              <div className="w-full h-full border-none rounded-none overflow-hidden flex flex-col bg-white">
                <iframe
                  ref={iframeRef}
                  title="Preview"
                  className="w-full flex-1 bg-white"
                />
              </div>
            ) : (
              <pre className="w-full h-full p-6 overflow-auto bg-slate-900 text-slate-100 font-mono text-xs sm:text-sm leading-relaxed scrollbar-thin scrollbar-thumb-slate-700">
                {currentCode || '// Source code will appear here...'}
              </pre>
            )}
          </div>
        </section>
      </main>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

        /* Transition tweaks for dark mode */
        html.dark body {
          background-color: #020617;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { generateWebPage, redefineWebPage, generateTemplateSuggestions } from './services/geminiService';
import { GenerationState, GeneratedPage, Template } from './types';

type Language = 'en' | 'bm';
type Theme = 'light' | 'dark';

const TRANSLATIONS = {
  en: {
    generateNew: "Generate New Page",
    placeholderPrompt: "Describe what you want to build... (e.g. 'A modern landing page for a coffee shop')",
    generateBtn: "Generate Page",
    refineTitle: "Refine Current Page",
    openEdit: "Open Edit",
    refinePlaceholder: "What would you like to change?",
    applyChanges: "Apply Changes",
    cancel: "Cancel",
    refineTip: "Use this to add features or tweak the design of the visible page.",
    historyTitle: "Versions & History",
    noPages: "No pages generated yet.",
    preview: "Preview",
    code: "Source Code",
    modify: "Modify",
    export: "Export",
    copy: "Copy",
    emptyTitle: "Build something incredible",
    emptySubtitle: "Select a template idea below or enter your own description to start generating a professional website.",
    suggestedTemplates: "Suggested Templates",
    refreshIdeas: "Refresh AI Ideas",
    refining: "Refining your page...",
    brewing: "Brewing your website...",
    secondsTip: "This usually takes about 10-15 seconds.",
    word: "Ubah",
    language: "Language",
    copied: "Code copied to clipboard!",
    genericError: "An unexpected error occurred.",
    themeDay: "Day Mode",
    themeNight: "Night Mode"
  },
  bm: {
    generateNew: "Jana Halaman Baru",
    placeholderPrompt: "Huraikan apa yang ingin anda bina... (cth. 'Halaman pendaratan moden untuk kedai kopi')",
    generateBtn: "Jana Halaman",
    refineTitle: "Kemaskini Halaman Semasa",
    openEdit: "Buka Suntingan",
    refinePlaceholder: "Apa yang ingin anda ubah?",
    applyChanges: "Simpan Perubahan",
    cancel: "Batal",
    refineTip: "Gunakan ini untuk menambah ciri atau mengubah reka bentuk halaman.",
    historyTitle: "Versi & Sejarah",
    noPages: "Tiada halaman dijana lagi.",
    preview: "Pratonton",
    code: "Kod Sumber",
    modify: "Ubah",
    export: "Eksport",
    copy: "Salin",
    emptyTitle: "Bina Sesuatu yang Luar Biasa",
    emptySubtitle: "Pilih idea templat di bawah atau masukkan huraian anda sendiri untuk mula menjana laman web profesional.",
    suggestedTemplates: "Templat Cadangan",
    refreshIdeas: "Segarkan Idea AI",
    refining: "Mengemaskini halaman anda...",
    brewing: "Menyediakan laman web anda...",
    secondsTip: "Ini biasanya mengambil masa 10-15 saat.",
    word: "Ubah",
    language: "Bahasa",
    copied: "Kod disalin ke papan klip!",
    genericError: "Ralat tidak dijangka berlaku.",
    themeDay: "Mod Siang",
    themeNight: "Mod Malam"
  }
};

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('instapage_lang') as Language) || 'en';
  });

  const [theme, setTheme] = useState<Theme>(() => {
    return (localStorage.getItem('instapage_theme') as Theme) || 'light';
  });

  const t = TRANSLATIONS[lang];

  const [prompt, setPrompt] = useState('');
  const [redefinePrompt, setRedefinePrompt] = useState('');
  const [status, setStatus] = useState<GenerationState>(GenerationState.IDLE);
  const [error, setError] = useState<string | null>(null);
  const [currentCode, setCurrentCode] = useState<string>('');
  const [activeId, setActiveId] = useState<string | null>(null);
  const [history, setHistory] = useState<GeneratedPage[]>([]);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [isRedefineOpen, setIsRedefineOpen] = useState(false);

  const [templates, setTemplates] = useState<Template[]>([]);
  const [isGeneratingTemplates, setIsGeneratingTemplates] = useState(false);

  const iframeRef = useRef<HTMLIFrameElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    localStorage.setItem('instapage_lang', lang);
  }, [lang]);

  useEffect(() => {
    localStorage.setItem('instapage_theme', theme);
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  useEffect(() => {
    refreshTemplates();
  }, [lang]);

  const refreshTemplates = async () => {
    setIsGeneratingTemplates(true);
    try {
      const suggested = await generateTemplateSuggestions(lang);
      setTemplates(suggested);
    } catch (err) {
      console.error("Failed to load templates", err);
    } finally {
      setIsGeneratingTemplates(false);
    }
  };

  useEffect(() => {
    if (viewMode === 'preview' && iframeRef.current && currentCode) {
      const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
      if (doc) {
        doc.open();
        doc.write(currentCode);
        doc.close();
      }
    }
  }, [currentCode, viewMode]);

  const handleGenerate = async (customPrompt?: string) => {
    const finalPrompt = (customPrompt || prompt).trim();
    if (!finalPrompt) return;

    setStatus(GenerationState.LOADING);
    setError(null);

    try {
      const code = await generateWebPage(finalPrompt);
      setCurrentCode(code);

      const newPage: GeneratedPage = {
        id: Date.now().toString(),
        name: finalPrompt.substring(0, 30) + (finalPrompt.length > 30 ? '...' : ''),
        html: code,
        createdAt: Date.now(),
      };

      setHistory(prev => [newPage, ...prev]);
      setActiveId(newPage.id);
      setStatus(GenerationState.SUCCESS);
      setPrompt(''); // Clear prompt after success
    } catch (err: any) {
      setStatus(GenerationState.ERROR);
      setError(err.message || t.genericError);
    }
  };

  const handleRedefine = async () => {
    const finalInstructions = redefinePrompt.trim();
    if (!finalInstructions || !currentCode || !activeId) return;

    setStatus(GenerationState.LOADING);
    setError(null);

    try {
      const updatedCode = await redefineWebPage(currentCode, finalInstructions);
      setCurrentCode(updatedCode);

      const newId = Date.now().toString();
      const newPage: GeneratedPage = {
        id: newId,
        name: `${lang === 'en' ? 'Refine' : 'Ubah'}: ${finalInstructions.substring(0, 20)}...`,
        html: updatedCode,
        createdAt: Date.now(),
        parentId: activeId,
      };

      setHistory(prev => [newPage, ...prev]);
      setActiveId(newId);
      setRedefinePrompt('');
      setIsRedefineOpen(false);
      setStatus(GenerationState.SUCCESS);
    } catch (err: any) {
      setStatus(GenerationState.ERROR);
      setError(err.message || t.genericError);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(currentCode);
    alert(t.copied);
  };

  const downloadFile = () => {
    const blob = new Blob([currentCode], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'index.html';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const selectFromHistory = (page: GeneratedPage) => {
    setCurrentCode(page.html);
    setActiveId(page.id);
    setIsRedefineOpen(false);
    setViewMode('preview');
  };

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const renderHistoryItem = (page: GeneratedPage, depth: number = 0) => {
    const children = history.filter(item => item.parentId === page.id);
    const isActive = activeId === page.id;

    return (
      <div key={page.id} className="flex flex-col">
        <button
          onClick={() => selectFromHistory(page)}
          className={`w-full text-left p-2 rounded-lg border transition-all text-xs flex justify-between items-center group mb-1 ${
            isActive 
              ? 'border-indigo-600 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300' 
              : 'border-slate-100 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-400'
          }`}
          style={{ marginLeft: `${depth * 16}px` }}
        >
          <div className="flex items-center gap-2 truncate">
            {depth > 0 && <i className="fa-solid fa-turn-up rotate-90 text-[10px] text-slate-300 dark:text-slate-600"></i>}
            <span className="truncate pr-1 font-medium">{page.name}</span>
          </div>
          <i className={`fa-solid fa-chevron-right text-[10px] transition-transform ${isActive ? 'translate-x-1' : ''}`}></i>
        </button>
        {children.length > 0 && (
          <div className="border-l border-slate-100 dark:border-slate-700 ml-2">
            {children.map(child => renderHistoryItem(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };

  const rootHistory = history.filter(item => !item.parentId);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-slate-100 transition-colors duration-300">
      <header className="bg-white dark:bg-slate-900 border-b dark:border-slate-800 px-6 py-4 flex items-center justify-between sticky top-0 z-50 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <i className="fa-solid fa-wand-magic-sparkles text-white text-xl"></i>
          </div>
          <h1 className="text-xl font-bold bg-gradient-to-r from-indigo-600 to-violet-600 bg-clip-text text-transparent">
            InstaPage AI
          </h1>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={toggleTheme}
            className="p-2 w-10 h-10 flex items-center justify-center rounded-full bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-400 transition-all border border-transparent dark:border-slate-700"
            title={theme === 'light' ? t.themeNight : t.themeDay}
          >
            {theme === 'light' ? <i className="fa-solid fa-moon"></i> : <i className="fa-solid fa-sun"></i>}
          </button>

          <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 p-1 rounded-full border border-transparent dark:border-slate-700">
            <button 
              onClick={() => setLang('en')}
              className={`px-3 py-1 text-xs font-bold rounded-full transition-all ${lang === 'en' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700'}`}
            >
              EN
            </button>
            <button 
              onClick={() => setLang('bm')}
              className={`px-3 py-1 text-xs font-bold rounded-full transition-all ${lang === 'bm' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700'}`}
            >
              BM
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 flex flex-col md:flex-row h-[calc(100vh-73px)] overflow-hidden">
        <aside className="w-full md:w-[400px] bg-white dark:bg-slate-900 border-r dark:border-slate-800 flex flex-col overflow-y-auto p-6 space-y-6 shadow-xl z-20">
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                {t.generateNew}
              </label>
              <textarea
                className="w-full h-40 p-3 border dark:border-slate-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 resize-none transition-all outline-none bg-slate-50 dark:bg-slate-800 text-sm shadow-inner dark:text-slate-100"
                placeholder={t.placeholderPrompt}
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
              />
              <button
                onClick={() => handleGenerate()}
                disabled={status === GenerationState.LOADING || !prompt.trim()}
                className={`w-full mt-2 py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all text-sm shadow-lg ${
                  status === GenerationState.LOADING || !prompt.trim()
                    ? 'bg-slate-200 dark:bg-slate-800 text-slate-400 dark:text-slate-600 cursor-not-allowed' 
                    : 'bg-indigo-600 hover:bg-indigo-700 text-white active:scale-95'
                }`}
              >
                {status === GenerationState.LOADING && !isRedefineOpen ? (
                  <i className="fa-solid fa-circle-notch animate-spin"></i>
                ) : (
                  <i className="fa-solid fa-sparkles"></i>
                )}
                {t.generateBtn}
              </button>
            </div>

            {currentCode && (
              <div className={`p-4 rounded-xl border-2 transition-all ${isRedefineOpen ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-900/10' : 'border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/50'}`}>
                <div className="flex items-center justify-between mb-2">
                  <label className="block text-sm font-bold text-slate-700 dark:text-slate-300">
                    {t.refineTitle}
                  </label>
                  {!isRedefineOpen && (
                    <button 
                      onClick={() => setIsRedefineOpen(true)}
                      className="text-xs text-indigo-600 dark:text-indigo-400 font-semibold hover:underline"
                    >
                      {t.openEdit}
                    </button>
                  )}
                </div>
                {isRedefineOpen ? (
                  <div className="space-y-3">
                    <textarea
                      className="w-full h-24 p-3 border border-indigo-200 dark:border-indigo-900 rounded-lg focus:ring-2 focus:ring-indigo-500 resize-none transition-all outline-none bg-white dark:bg-slate-800 text-sm dark:text-slate-100"
                      placeholder={t.refinePlaceholder}
                      value={redefinePrompt}
                      onChange={(e) => setRedefinePrompt(e.target.value)}
                      autoFocus
                    />
                    <div className="flex gap-2">
                      <button
                        onClick={handleRedefine}
                        disabled={status === GenerationState.LOADING || !redefinePrompt.trim()}
                        className="flex-1 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 disabled:opacity-50"
                      >
                        {status === GenerationState.LOADING && isRedefineOpen ? <i className="fa-solid fa-circle-notch animate-spin"></i> : <i className="fa-solid fa-wand-sparkles"></i>}
                        {t.applyChanges}
                      </button>
                      <button
                        onClick={() => { setIsRedefineOpen(false); setRedefinePrompt(''); }}
                        className="px-3 py-2 bg-white dark:bg-slate-700 border dark:border-slate-600 text-slate-500 dark:text-slate-300 rounded-lg text-sm hover:bg-slate-50 dark:hover:bg-slate-600"
                      >
                        {t.cancel}
                      </button>
                    </div>
                  </div>
                ) : (
                  <p className="text-xs text-slate-500 dark:text-slate-400 italic">{t.refineTip}</p>
                )}
              </div>
            )}
          </div>

          <div className="flex-1 flex flex-col min-h-0">
            <h3 className="text-sm font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 flex items-center justify-between">
              <span>{t.historyTitle}</span>
              <span className="text-[10px] bg-slate-100 dark:bg-slate-800 px-2 py-0.5 rounded-full">{history.length}</span>
            </h3>
            <div className="flex-1 overflow-y-auto space-y-4 pr-1 scrollbar-thin">
              {rootHistory.length === 0 ? (
                <div className="text-center py-8 text-slate-400 dark:text-slate-600 italic text-sm border border-dashed border-slate-200 dark:border-slate-800 rounded-xl">
                  {t.noPages}
                </div>
              ) : (
                rootHistory.map(rootPage => renderHistoryItem(rootPage))
              )}
            </div>
          </div>
        </aside>

        <section className="flex-1 bg-slate-100 dark:bg-slate-950 p-4 flex flex-col overflow-hidden relative">
          <div className="bg-white dark:bg-slate-900 rounded-t-xl border-x border-t dark:border-slate-800 p-2 flex flex-wrap items-center justify-between shadow-sm gap-y-2">
            <div className="flex items-center gap-2">
              <button
                onClick={() => setViewMode('preview')}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${
                  viewMode === 'preview' ? 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-300' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'
                }`}
              >
                <i className="fa-solid fa-eye mr-2"></i>
                {t.preview}
              </button>
              <button
                onClick={() => setViewMode('code')}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${
                  viewMode === 'code' ? 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-300' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'
                }`}
              >
                <i className="fa-solid fa-code mr-2"></i>
                {t.code}
              </button>
            </div>

            {currentCode && (
              <div className="flex items-center gap-2">
                <button
                  onClick={copyToClipboard}
                  className="p-2 text-slate-500 dark:text-slate-400 hover:text-indigo-600 transition-colors"
                  title={t.copy}
                >
                  <i className="fa-solid fa-copy"></i>
                </button>
                <button
                  onClick={downloadFile}
                  className="bg-slate-900 dark:bg-slate-100 dark:text-slate-900 text-white px-4 py-1.5 rounded-lg text-sm font-medium hover:bg-slate-800 dark:hover:bg-white transition-all flex items-center gap-2"
                >
                  <i className="fa-solid fa-download"></i>
                  {t.export}
                </button>
              </div>
            )}
          </div>

          <div 
            ref={previewContainerRef}
            className="flex-1 bg-white dark:bg-slate-900 border dark:border-slate-800 rounded-b-xl shadow-inner relative overflow-hidden flex flex-col items-center justify-center transition-colors duration-300"
          >
            {error && (
              <div className="absolute top-4 left-1/2 -translate-x-1/2 z-40 bg-red-50 dark:bg-red-900/20 border border-red-100 dark:border-red-900/50 p-3 rounded-lg text-red-600 dark:text-red-400 text-xs flex items-center gap-3 shadow-lg">
                <i className="fa-solid fa-circle-exclamation"></i>
                <span>{error}</span>
                <button onClick={() => setError(null)} className="ml-2 hover:opacity-70"><i className="fa-solid fa-xmark"></i></button>
              </div>
            )}

            {!currentCode && status !== GenerationState.LOADING && (
              <div className="absolute inset-0 flex flex-col items-center justify-start text-slate-300 dark:text-slate-700 p-8 pt-16 overflow-y-auto bg-white dark:bg-slate-900">
                <div className="bg-indigo-50 dark:bg-indigo-900/20 p-6 rounded-full mb-6">
                  <i className="fa-solid fa-magic-wand-sparkles text-5xl text-indigo-600 opacity-60"></i>
                </div>
                <h2 className="text-2xl font-bold text-slate-800 dark:text-slate-100 mb-2">{t.emptyTitle}</h2>
                <p className="text-sm text-slate-500 dark:text-slate-400 mb-8 max-w-md text-center">{t.emptySubtitle}</p>

                <div className="w-full max-w-4xl">
                  <div className="flex items-center justify-between mb-4 px-2">
                    <h3 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t.suggestedTemplates}</h3>
                    <button 
                      onClick={refreshTemplates}
                      disabled={isGeneratingTemplates}
                      className="text-xs font-bold text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 flex items-center gap-2 transition-colors disabled:opacity-50"
                    >
                      <i className={`fa-solid fa-rotate ${isGeneratingTemplates ? 'animate-spin' : ''}`}></i>
                      {t.refreshIdeas}
                    </button>
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    {isGeneratingTemplates ? (
                      Array(6).fill(0).map((_, i) => (
                        <div key={i} className="h-32 bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-xl animate-pulse"></div>
                      ))
                    ) : (
                      templates.map((temp) => (
                        <button
                          key={temp.id}
                          onClick={() => handleGenerate(temp.prompt)}
                          className="group text-left p-5 bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl hover:border-indigo-500 hover:shadow-xl hover:shadow-indigo-50/50 dark:hover:shadow-none transition-all duration-300 active:scale-95"
                        >
                          <div className="w-10 h-10 mb-4 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl flex items-center justify-center text-indigo-600 dark:text-indigo-400 group-hover:scale-110 transition-transform">
                            <i className={`fa-solid ${temp.icon} text-lg`}></i>
                          </div>
                          <h4 className="font-bold text-slate-800 dark:text-slate-100 mb-1 group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{temp.name}</h4>
                          <p className="text-xs text-slate-500 dark:text-slate-400 line-clamp-2 leading-relaxed">{temp.description}</p>
                        </button>
                      ))
                    )}
                  </div>
                </div>
              </div>
            )}

            {status === GenerationState.LOADING && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/95 dark:bg-slate-900/95 backdrop-blur-sm z-30">
                <div className="relative">
                  <div className="w-20 h-20 border-4 border-indigo-100 dark:border-indigo-900 border-t-indigo-600 rounded-full animate-spin mb-6"></div>
                  <i className="fa-solid fa-magic-wand-sparkles absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-[60%] text-indigo-600 text-xl animate-pulse"></i>
                </div>
                <p className="text-indigo-900 dark:text-indigo-300 font-bold text-xl tracking-tight text-center">
                  {isRedefineOpen ? t.refining : t.brewing}
                </p>
                <p className="text-slate-500 dark:text-slate-400 text-sm mt-3 font-medium">{t.secondsTip}</p>
              </div>
            )}

            {viewMode === 'preview' ? (
              <div className="w-full h-full border-none rounded-none overflow-hidden flex flex-col bg-white">
                <iframe
                  ref={iframeRef}
                  title="Preview"
                  className="w-full flex-1 bg-white"
                />
              </div>
            ) : (
              <pre className="w-full h-full p-6 overflow-auto bg-slate-900 text-slate-100 font-mono text-xs sm:text-sm leading-relaxed scrollbar-thin scrollbar-thumb-slate-700">
                {currentCode || '// Source code will appear here...'}
              </pre>
            )}
          </div>
        </section>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

export const generateWebPage = async (prompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemInstruction = `
    You are an expert senior web designer and frontend developer.
    Your task is to generate a single, complete, and functional HTML file based on the user's request.

    RULES:
    1. Output ONLY a valid, standalone HTML file. 
    2. Include all CSS within a <style> tag in the <head>.
    3. Include all JavaScript within a <script> tag before the </body>.
    4. Use ONLY Vanilla JavaScript and raw CSS. No external frameworks (React, Vue, Bootstrap, etc.).
    5. The design must be modern, responsive (mobile-first), and aesthetically pleasing.
    6. Include placeholder images using https://picsum.photos/ or professional-looking SVGs.
    7. Ensure the code is clean, commented, and professional.
    8. Do not add any text before or after the HTML block.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.7,
      },
    });

    const text = response.text || "";
    const cleanedText = text.replace(/```html/g, "").replace(/```/g, "").trim();
    return cleanedText;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to generate code / Gagal menjana kod.");
  }
};

export const redefineWebPage = async (currentCode: string, instructions: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemInstruction = `
    You are an expert web developer specializing in refactoring and updating code.
    You will be provided with an existing standalone HTML/CSS/JS file and instructions for modifications.

    RULES:
    1. Modify the existing code based on the instructions provided.
    2. Maintain the overall structure and style unless asked to change them.
    3. Ensure the updated code is complete, functional, and remains a standalone single HTML file.
    4. Return ONLY the full updated HTML code. No explanations.
    5. Continue using only Vanilla JS and CSS.
  `;

  const contents = [
    { text: `EXISTING CODE:\n${currentCode}` },
    { text: `MODIFICATION INSTRUCTIONS:\n${instructions}` }
  ];

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: { parts: contents },
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.5,
      },
    });

    const text = response.text || "";
    const cleanedText = text.replace(/```html/g, "").replace(/```/g, "").trim();
    return cleanedText;
  } catch (error) {
    console.error("Gemini API Error (Redefine):", error);
    throw new Error("Failed to update code / Gagal mengemaskini kod.");
  }
};

