const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('instapage_lang') as Language) || 'en';
  });

  const [theme, setTheme] = useState<Theme>(() => {
    return (localStorage.getItem('instapage_theme') as Theme) || 'light';
  });

  const [selectedModel, setSelectedModel] = useState<AIModel>(() => {
    return (localStorage.getItem('instapage_model') as AIModel) || 'gemini-3-flash-preview';
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const t = TRANSLATIONS[lang];

  const [prompt, setPrompt] = useState('');
  const [redefinePrompt, setRedefinePrompt] = useState('');
  const [status, setStatus] = useState<GenerationState>(GenerationState.IDLE);
  const [error, setError] = useState<string | null>(null);
  const [currentCode, setCurrentCode] = useState<string>('');
  const [activeId, setActiveId] = useState<string | null>(null);
  const [history, setHistory] = useState<GeneratedPage[]>([]);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [isRedefineOpen, setIsRedefineOpen] = useState(false);

  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => {
    localStorage.setItem('instapage_lang', lang);
  }, [lang]);

  useEffect(() => {
    localStorage.setItem('instapage_theme', theme);
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('instapage_model', selectedModel);
  }, [selectedModel]);

  useEffect(() => {
    if (viewMode === 'preview' && iframeRef.current && currentCode) {
      const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
      if (doc) {
        doc.open();
        doc.write(currentCode);
        doc.close();
      }
    }
  }, [currentCode, viewMode]);

  const handleGenerate = async () => {
    const finalPrompt = prompt.trim();
    if (!finalPrompt) return;

    setStatus(GenerationState.LOADING);
    setError(null);

    try {
      const code = await generateWebPage(finalPrompt, selectedModel);
      setCurrentCode(code);

      const newPage: GeneratedPage = {
        id: Date.now().toString(),
        name: finalPrompt.substring(0, 30) + (finalPrompt.length > 30 ? '...' : ''),
        html: code,
        createdAt: Date.now(),
      };

      setHistory(prev => [newPage, ...prev]);
      setActiveId(newPage.id);
      setStatus(GenerationState.SUCCESS);
      setPrompt(''); 
    } catch (err: any) {
      setStatus(GenerationState.ERROR);
      setError(err.message || t.genericError);
    }
  };

  const handleRedefine = async () => {
    const finalInstructions = redefinePrompt.trim();
    if (!finalInstructions || !currentCode || !activeId) return;

    setStatus(GenerationState.LOADING);
    setError(null);

    try {
      const updatedCode = await redefineWebPage(currentCode, finalInstructions, selectedModel);
      setCurrentCode(updatedCode);

      const newId = Date.now().toString();
      const newPage: GeneratedPage = {
        id: newId,
        name: `${lang === 'en' ? 'Refine' : 'Ubah'}: ${finalInstructions.substring(0, 20)}...`,
        html: updatedCode,
        createdAt: Date.now(),
        parentId: activeId,
      };

      setHistory(prev => [newPage, ...prev]);
      setActiveId(newId);
      setRedefinePrompt('');
      setIsRedefineOpen(false);
      setStatus(GenerationState.SUCCESS);
