              </div>
            )}
          </div>

          <div className="flex-1 flex flex-col min-h-0">
            <h3 className="text-sm font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 flex items-center justify-between">
              <span>{t.historyTitle}</span>
              <span className="text-[10px] bg-slate-100 dark:bg-slate-800 px-2 py-0.5 rounded-full">{history.length}</span>
            </h3>
            <div className="flex-1 overflow-y-auto space-y-4 pr-1 scrollbar-thin">
              {rootHistory.length === 0 ? (
                <div className="text-center py-8 text-slate-400 dark:text-slate-600 italic text-sm border border-dashed border-slate-200 dark:border-slate-800 rounded-xl">
                  {t.noPages}
                </div>
              ) : (
                rootHistory.map(rootPage => renderHistoryItem(rootPage))
              )}
            </div>
          </div>
        </aside>

        <section className="flex-1 bg-slate-100 dark:bg-slate-950 p-4 flex flex-col overflow-hidden relative">
          <div className="bg-white dark:bg-slate-900 rounded-t-xl border-x border-t dark:border-slate-800 p-2 flex flex-wrap items-center justify-between shadow-sm gap-y-2">
            <div className="flex items-center gap-2">
              <button
                onClick={() => setViewMode('preview')}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${
                  viewMode === 'preview' ? 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-300' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'
                }`}
              >
                <i className="fa-solid fa-eye mr-2"></i>
                {t.preview}
              </button>
              <button
                onClick={() => setViewMode('code')}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${
                  viewMode === 'code' ? 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-300' : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'
                }`}
              >
                <i className="fa-solid fa-code mr-2"></i>
                {t.code}
              </button>
            </div>

            {currentCode && (
              <div className="flex items-center gap-2">
                <button
                  onClick={copyToClipboard}
                  className="p-2 text-slate-500 dark:text-slate-400 hover:text-indigo-600 transition-colors"
                  title={t.copy}
                >
                  <i className="fa-solid fa-copy"></i>
                </button>
                <button
                  onClick={downloadFile}
                  className="bg-slate-900 dark:bg-slate-100 dark:text-slate-900 text-white px-4 py-1.5 rounded-lg text-sm font-medium hover:bg-slate-800 dark:hover:bg-white transition-all flex items-center gap-2"
                >
                  <i className="fa-solid fa-download"></i>
                  {t.export}
                </button>
              </div>
            )}
          </div>

          <div className="flex-1 bg-white dark:bg-slate-900 border dark:border-slate-800 rounded-b-xl shadow-inner relative overflow-hidden flex flex-col items-center justify-center transition-colors duration-300">
            {error && (
              <div className="absolute top-4 left-1/2 -translate-x-1/2 z-40 bg-red-50 dark:bg-red-900/20 border border-red-100 dark:border-red-900/50 p-3 rounded-lg text-red-600 dark:text-red-400 text-xs flex items-center gap-3 shadow-lg">
                <i className="fa-solid fa-circle-exclamation"></i>
                <span>{error}</span>
                <button onClick={() => setError(null)} className="ml-2 hover:opacity-70"><i className="fa-solid fa-xmark"></i></button>
              </div>
            )}

            {!currentCode && status !== GenerationState.LOADING && (
              <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300 dark:text-slate-700 p-8 overflow-y-auto bg-white dark:bg-slate-900">
                <div className="bg-indigo-50 dark:bg-indigo-900/20 p-8 rounded-full mb-8">
                  <i className="fa-solid fa-magic-wand-sparkles text-6xl text-indigo-600 opacity-60"></i>
                </div>
                <h2 className="text-3xl font-bold text-slate-800 dark:text-slate-100 mb-3">{t.emptyTitle}</h2>
                <p className="text-base text-slate-500 dark:text-slate-400 max-w-md text-center">{t.emptySubtitle}</p>
                <div className="mt-6 flex items-center gap-2 text-xs font-medium text-slate-400 border border-slate-100 dark:border-slate-800 px-4 py-2 rounded-full">
                  <i className="fa-solid fa-robot"></i>
                  <span>Using: {selectedModel.includes('pro') ? t.proName : t.flashName}</span>
                </div>
              </div>
            )}

            {status === GenerationState.LOADING && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/95 dark:bg-slate-900/95 backdrop-blur-sm z-30">
                <div className="relative">
                  <div className="w-20 h-20 border-4 border-indigo-100 dark:border-indigo-900 border-t-indigo-600 rounded-full animate-spin mb-6"></div>
                  <i className="fa-solid fa-magic-wand-sparkles absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-[60%] text-indigo-600 text-xl animate-pulse"></i>
                </div>
                <p className="text-indigo-900 dark:text-indigo-300 font-bold text-xl tracking-tight text-center">
                  {isRedefineOpen ? t.refining : t.brewing}
                </p>
                <p className="text-slate-500 dark:text-slate-400 text-sm mt-3 font-medium">
                  {selectedModel.includes('pro') ? "Pro engine is more powerful but may take longer..." : t.secondsTip}
                </p>
              </div>
            )}

            {viewMode === 'preview' ? (
              <div className="w-full h-full border-none rounded-none overflow-hidden flex flex-col bg-white">
                <iframe
                  ref={iframeRef}
                  title="Preview"
                  className="w-full flex-1 bg-white"
                />
              </div>
            ) : (
              <pre className="w-full h-full p-6 overflow-auto bg-slate-900 text-slate-100 font-mono text-xs sm:text-sm leading-relaxed scrollbar-thin scrollbar-thumb-slate-700">
                {currentCode || '// Source code will appear here...'}
              </pre>
            )}
          </div>
        </section>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
