const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('instapage_lang') as Language) || 'en';
  });

  const [theme, setTheme] = useState<Theme>(() => {
    return (localStorage.getItem('instapage_theme') as Theme) || 'light';
  });

  const [selectedModel, setSelectedModel] = useState<AIModel>(() => {
    return (localStorage.getItem('instapage_model') as AIModel) || 'gemini-3-flash-preview';
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const t = TRANSLATIONS[lang];

  const [prompt, setPrompt] = useState('');
  const [redefinePrompt, setRedefinePrompt] = useState('');
  const [status, setStatus] = useState<GenerationState>(GenerationState.IDLE);
  const [error, setError] = useState<string | null>(null);
  const [currentCode, setCurrentCode] = useState<string>('');
  const [activeId, setActiveId] = useState<string | null>(null);
  const [history, setHistory] = useState<GeneratedPage[]>([]);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [isRedefineOpen, setIsRedefineOpen] = useState(false);

  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => {
    localStorage.setItem('instapage_lang', lang);
  }, [lang]);

  useEffect(() => {
    localStorage.setItem('instapage_theme', theme);
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('instapage_model', selectedModel);
  }, [selectedModel]);

  useEffect(() => {
    if (viewMode === 'preview' && iframeRef.current && currentCode) {
      const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow?.document;
      if (doc) {
        doc.open();
        doc.write(currentCode);
        doc.close();
      }
    }
  }, [currentCode, viewMode]);

  const handleGenerate = async () => {
    const finalPrompt = prompt.trim();
    if (!finalPrompt) return;

    setStatus(GenerationState.LOADING);
    setError(null);

    try {
      const code = await generateWebPage(finalPrompt, selectedModel);
      setCurrentCode(code);

      const newPage: GeneratedPage = {
        id: Date.now().toString(),
        name: finalPrompt.substring(0, 30) + (finalPrompt.length > 30 ? '...' : ''),
        html: code,
        createdAt: Date.now(),
      };

      setHistory(prev => [newPage, ...prev]);
      setActiveId(newPage.id);
      setStatus(GenerationState.SUCCESS);
      setPrompt(''); 
    } catch (err: any) {
      setStatus(GenerationState.ERROR);
      setError(err.message || t.genericError);
    }
  };

  const handleRedefine = async () => {
    const finalInstructions = redefinePrompt.trim();
    if (!finalInstructions || !currentCode || !activeId) return;

    setStatus(GenerationState.LOADING);
    setError(null);

    try {
      const updatedCode = await redefineWebPage(currentCode, finalInstructions, selectedModel);
      setCurrentCode(updatedCode);

      const newId = Date.now().toString();
      const newPage: GeneratedPage = {
        id: newId,
        name: `${lang === 'en' ? 'Refine' : 'Ubah'}: ${finalInstructions.substring(0, 20)}...`,
        html: updatedCode,
        createdAt: Date.now(),
        parentId: activeId,
      };

      setHistory(prev => [newPage, ...prev]);
      setActiveId(newId);
      setRedefinePrompt('');
      setIsRedefineOpen(false);
      setStatus(GenerationState.SUCCESS);
    } catch (err: any) {
      setStatus(GenerationState.ERROR);
      setError(err.message || t.genericError);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(currentCode);
    alert(t.copied);
  };

  const downloadFile = () => {
    const blob = new Blob([currentCode], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'index.html';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const selectFromHistory = (page: GeneratedPage) => {
    setCurrentCode(page.html);
    setActiveId(page.id);
    setIsRedefineOpen(false);
    setViewMode('preview');
  };

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const renderHistoryItem = (page: GeneratedPage, depth: number = 0) => {
    const children = history.filter(item => item.parentId === page.id);
    const isActive = activeId === page.id;

    return (
      <div key={page.id} className="flex flex-col">
        <button
          onClick={() => selectFromHistory(page)}
          className={`w-full text-left p-2 rounded-lg border transition-all text-xs flex justify-between items-center group mb-1 ${
            isActive 
              ? 'border-indigo-600 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300' 
              : 'border-slate-100 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-400'
          }`}
          style={{ marginLeft: `${depth * 16}px` }}
        >
          <div className="flex items-center gap-2 truncate">
            {depth > 0 && <i className="fa-solid fa-turn-up rotate-90 text-[10px] text-slate-300 dark:text-slate-600"></i>}
            <span className="truncate pr-1 font-medium">{page.name}</span>
          </div>
          <i className={`fa-solid fa-chevron-right text-[10px] transition-transform ${isActive ? 'translate-x-1' : ''}`}></i>
        </button>
        {children.length > 0 && (
          <div className="border-l border-slate-100 dark:border-slate-700 ml-2">
            {children.map(child => renderHistoryItem(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };

  const rootHistory = history.filter(item => !item.parentId);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-slate-100 transition-colors duration-300">
      {/* Settings Modal */}
      {isSettingsOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-2xl shadow-2xl border dark:border-slate-800 overflow-hidden transform animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b dark:border-slate-800 flex items-center justify-between">
              <h2 className="text-xl font-bold flex items-center gap-2">
                <i className="fa-solid fa-sliders text-indigo-600"></i>
                {t.settings}
              </h2>
              <button onClick={() => setIsSettingsOpen(false)} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>
            <div className="p-6 space-y-6 max-h-[60vh] overflow-y-auto">
              <div>
                <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-4">{t.aiEngine}</label>
                <div className="grid grid-cols-1 gap-3">
                  <button 
                    onClick={() => setSelectedModel('gemini-2.5-flash-latest')}
                    className={`w-full p-4 rounded-xl border-2 text-left transition-all ${selectedModel === 'gemini-2.5-flash-latest' ? 'border-indigo-600 bg-indigo-50 dark:bg-indigo-900/20' : 'border-slate-100 dark:border-slate-800 hover:border-slate-200 dark:hover:border-slate-700'}`}
                  >
                    <div className="flex items-center justify-between mb-1">
                      <span className="font-bold text-slate-800 dark:text-slate-100">{t.flash25Name}</span>
                      {selectedModel === 'gemini-2.5-flash-latest' && <i className="fa-solid fa-circle-check text-indigo-600"></i>}
                    </div>
                    <p className="text-xs text-slate-500 dark:text-slate-400">{t.flash25Desc}</p>
                  </button>

                  <button 
                    onClick={() => setSelectedModel('gemini-2.5-pro-latest')}
                    className={`w-full p-4 rounded-xl border-2 text-left transition-all ${selectedModel === 'gemini-2.5-pro-latest' ? 'border-indigo-600 bg-indigo-50 dark:bg-indigo-900/20' : 'border-slate-100 dark:border-slate-800 hover:border-slate-200 dark:hover:border-slate-700'}`}
                  >
                    <div className="flex items-center justify-between mb-1">
                      <span className="font-bold text-slate-800 dark:text-slate-100">{t.pro25Name}</span>
                      {selectedModel === 'gemini-2.5-pro-latest' && <i className="fa-solid fa-circle-check text-indigo-600"></i>}
                    </div>
                    <p className="text-xs text-slate-500 dark:text-slate-400">{t.pro25Desc}</p>
                  </button>

                  <div className="h-[1px] bg-slate-100 dark:bg-slate-800 my-1"></div>

                  <button 
                    onClick={() => setSelectedModel('gemini-3-flash-preview')}
                    className={`w-full p-4 rounded-xl border-2 text-left transition-all ${selectedModel === 'gemini-3-flash-preview' ? 'border-indigo-600 bg-indigo-50 dark:bg-indigo-900/20' : 'border-slate-100 dark:border-slate-800 hover:border-slate-200 dark:hover:border-slate-700'}`}
                  >
                    <div className="flex items-center justify-between mb-1">
                      <span className="font-bold text-slate-800 dark:text-slate-100">{t.flash3Name}</span>
                      {selectedModel === 'gemini-3-flash-preview' && <i className="fa-solid fa-circle-check text-indigo-600"></i>}
                    </div>
                    <p className="text-xs text-slate-500 dark:text-slate-400">{t.flash3Desc}</p>
                  </button>

                  <button 
                    onClick={() => setSelectedModel('gemini-3-pro-preview')}
                    className={`w-full p-4 rounded-xl border-2 text-left transition-all ${selectedModel === 'gemini-3-pro-preview' ? 'border-indigo-600 bg-indigo-50 dark:bg-indigo-900/20' : 'border-slate-100 dark:border-slate-800 hover:border-slate-200 dark:hover:border-slate-700'}`}
                  >
                    <div className="flex items-center justify-between mb-1">
                      <span className="font-bold text-slate-800 dark:text-slate-100">{t.pro3Name}</span>
                      {selectedModel === 'gemini-3-pro-preview' && <i className="fa-solid fa-circle-check text-indigo-600"></i>}
                    </div>
                    <p className="text-xs text-slate-500 dark:text-slate-400">{t.pro3Desc}</p>
                  </button>
                </div>
              </div>
            </div>
            <div className="p-6 bg-slate-50 dark:bg-slate-800/50 border-t dark:border-slate-800">
              <button 
                onClick={() => setIsSettingsOpen(false)}
                className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold transition-all shadow-lg active:scale-[0.98]"
              >
                {t.save}
              </button>
            </div>
          </div>
        </div>
      )}

      <header className="bg-white dark:bg-slate-900 border-b dark:border-slate-800 px-6 py-4 flex items-center justify-between sticky top-0 z-50 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <i className="fa-solid fa-wand-magic-sparkles text-white text-xl"></i>
          </div>
          <h1 className="text-xl font-bold bg-gradient-to-r from-indigo-600 to-violet-600 bg-clip-text text-transparent">
            InstaPage AI
          </h1>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={() => setIsSettingsOpen(true)}
            className="p-2 w-10 h-10 flex items-center justify-center rounded-full bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-400 transition-all border border-transparent dark:border-slate-700"
            title={t.settings}
          >
            <i className="fa-solid fa-gear"></i>
          </button>

          <button 
            onClick={toggleTheme}
            className="p-2 w-10 h-10 flex items-center justify-center rounded-full bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-400 transition-all border border-transparent dark:border-slate-700"
            title={theme === 'light' ? t.themeNight : t.themeDay}
          >
            {theme === 'light' ? <i className="fa-solid fa-moon"></i> : <i className="fa-solid fa-sun"></i>}
          </button>

          <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 p-1 rounded-full border border-transparent dark:border-slate-700">
            <button 
              onClick={() => setLang('en')}
              className={`px-3 py-1 text-xs font-bold rounded-full transition-all ${lang === 'en' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700'}`}
            >
              EN
            </button>
            <button 
              onClick={() => setLang('bm')}
              className={`px-3 py-1 text-xs font-bold rounded-full transition-all ${lang === 'bm' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700'}`}
            >
              BM
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 flex flex-col md:flex-row h-[calc(100vh-73px)] overflow-hidden">
        <aside className="w-full md:w-[400px] bg-white dark:bg-slate-900 border-r dark:border-slate-800 flex flex-col overflow-y-auto p-6 space-y-6 shadow-xl z-20">
          <div className="space-y-4">
            <div>
              <div className="flex items-center justify-between mb-2">
                <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300">
