import { GoogleGenAI, Type } from "@google/genai";

const extractHtml = (text: string): string => {
  // Try to find content inside ```html ... ``` blocks
  const codeBlockMatch = text.match(/```html\s?([\s\S]*?)```/i);
  if (codeBlockMatch && codeBlockMatch[1]) {
    return codeBlockMatch[1].trim();
  }

  // Try to find content inside generic ``` ... ``` blocks
  const genericBlockMatch = text.match(/```\s?([\s\S]*?)```/i);
  if (genericBlockMatch && genericBlockMatch[1]) {
    return genericBlockMatch[1].trim();
  }

  // If no blocks, check if there's an <html> tag and extract from there
  const htmlTagMatch = text.match(/(<!DOCTYPE[\s\S]*?<\/html>|<html[\s\S]*?<\/html>)/i);
  if (htmlTagMatch && htmlTagMatch[0]) {
    return htmlTagMatch[0].trim();
  }

  // Fallback to the whole text if it looks like HTML
  if (text.toLowerCase().includes('<html')) {
    return text.trim();
  }

  throw new Error("AI did not return valid HTML code.");
};

export const generateWebPage = async (prompt: string, modelName: string = "gemini-3-flash-preview"): Promise<string> => {
  const apiKey = process.env.API_KEY;

  if (!apiKey || apiKey === 'PLACEHOLDER_API_KEY' || apiKey === 'undefined') {
    throw new Error("API Key is missing. Please set GEMINI_API_KEY in Vercel Environment Variables.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const systemInstruction = `
    You are an expert senior web designer and frontend developer.
    Your task is to generate a single, complete, and functional HTML file based on the user's request.

    RULES:
    1. Output ONLY a valid, standalone HTML file. 
    2. Include all CSS within a <style> tag in the <head>.
    3. Include all JavaScript within a <script> tag before the </body>.
    4. Use ONLY Vanilla JavaScript and raw CSS. No external frameworks.
    5. The design must be modern, responsive, and professional.
    6. Include placeholder images using https://picsum.photos/ or professional SVGs.
    7. Do not add any conversational text, explanations, or notes.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.7,
      },
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from AI");

    return extractHtml(text);
  } catch (error: any) {
    console.error(`Gemini API Error (Generate - ${modelName}):`, error);

    if (error.message?.includes("entity was not found")) {
      throw new Error(`Model ${modelName} not found. Try switching to Gemini 3 Flash in Settings.`);
    }

    const errorMsg = error.message?.includes("safety") 
      ? "Content blocked by safety filters." 
      : `Failed to generate code: ${error.message || 'Unknown error'}`;
    throw new Error(errorMsg);
  }
};

export const redefineWebPage = async (currentCode: string, instructions: string, modelName: string = "gemini-3-flash-preview"): Promise<string> => {
  const apiKey = process.env.API_KEY;

  if (!apiKey || apiKey === 'PLACEHOLDER_API_KEY' || apiKey === 'undefined') {
    throw new Error("API Key is missing. Please set GEMINI_API_KEY in Vercel Environment Variables.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const systemInstruction = `
    You are an expert web developer specializing in refactoring.
    You will be provided with an existing HTML file and instructions for modifications.

    RULES:
    1. Modify the existing code based on the instructions.
    2. Maintain the overall structure and style unless asked to change them.
    3. Ensure the updated code remains a standalone single HTML file.
    4. Return ONLY the full updated HTML code. No explanations.
    5. Continue using only Vanilla JS and CSS.
  `;

  const contents = [
    { text: `EXISTING CODE:\n${currentCode}` },
    { text: `MODIFICATION INSTRUCTIONS:\n${instructions}` }
  ];

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: { parts: contents },
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.4,
      },
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from AI");

    return extractHtml(text);
  } catch (error: any) {
    console.error(`Gemini API Error (Redefine - ${modelName}):`, error);
    const errorMsg = error.message?.includes("safety") 
      ? "Modification blocked by safety filters." 
      : `Failed to update code: ${error.message || 'Unknown error'}`;
    throw new Error(errorMsg);
  }
};

