import { GoogleGenAI } from "@google/genai";

export interface GenerationResult {
  code: string;
}

export async function generateAppCode(
  prompt: string, 
  model: string, 
  existingCode?: string, 
  signal?: AbortSignal
): Promise<GenerationResult> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemInstruction = existingCode 
    ? `You are a precision surgical code editor. You are modifying an existing single-file HTML application.

       STRICT SURGICAL RULES:
       1. ONLY modify the specific lines or elements requested.
       2. DO NOT refactor or rewrite unrelated sections.
       3. PRESERVE all existing comments and structure.
       4. Output the ENTIRE updated file starting with <!DOCTYPE html>.

       CRITICAL: YOUR RESPONSE MUST ONLY CONTAIN THE RAW HTML CODE. NO EXPLANATIONS. NO MARKDOWN BLOCKS.

       CURRENT CODE:
       ${existingCode}`
    : `You are an expert full-stack developer. 
       Generate a COMPLETE, functional, and beautiful single-file HTML application.
       Use Tailwind CSS via CDN. Ensure responsiveness.
       OUTPUT ONLY the raw HTML code starting with <!DOCTYPE html>. No markdown blocks.`;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: [{ text: prompt }],
      config: {
        systemInstruction: systemInstruction,
        temperature: existingCode ? 0.05 : 0.2,
      },
    });

    if (signal?.aborted) throw new Error("AbortError");

    const textOutput = response.text || "";
    return {
      code: textOutput.replace(/```html/g, '').replace(/```/g, '').trim()
    };
  } catch (error: any) {
    if (error.name === 'AbortError') throw new Error("Generation cancelled.");
    console.error("Gemini API Error:", error);
    throw new Error(`Generation failed: ${error.message}`);
  }
}

