  const [device, setDevice] = useState<PreviewDevice>(PreviewDevice.DESKTOP);
  const [orientation, setOrientation] = useState<Orientation>('portrait');
  const [history, setHistory] = useState<GeneratedProject[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });
  const [copied, setCopied] = useState(false);
  const [applySuccess, setApplySuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeProjectId, setActiveProjectId] = useState<string | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [selectedModel, setSelectedModel] = useState('gemini-3-flash-preview');
  const [previewKey, setPreviewKey] = useState(0);

  const abortControllerRef = useRef<AbortController | null>(null);

  // Sync history to localStorage whenever it changes
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(history));
  }, [history]);

  const saveProjectLocally = (project: GeneratedProject) => {
    setHistory(prev => {
      const index = prev.findIndex(p => p.id === project.id);
      if (index !== -1) {
        const next = [...prev];
        next[index] = project;
        return next;
      }
      return [project, ...prev];
    });
  };

  const handleCreateBlankProject = () => {
    const blankBoilerplate = `<!DOCTYPE html>\n<html lang="en">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>Blank Project</title>\n    <script src="https://cdn.tailwindcss.com"></script>\n</head>\n<body class="bg-white min-h-screen flex items-center justify-center font-sans text-gray-300 italic">\n    Empty Canvas\n</body>\n</html>`;
    const newProjectId = Date.now().toString();
    const newProject: GeneratedProject = { 
      id: newProjectId, 
      name: "Blank Project", 
      prompt: "Blank template", 
      code: blankBoilerplate, 
      timestamp: Date.now() 
    };
    setProjectTitle("Blank Project");
    setPrompt("");
    setCode(blankBoilerplate);
    setEditableCode(blankBoilerplate);
    setActiveProjectId(newProjectId);
    saveProjectLocally(newProject);
    setViewMode('preview');
    setIsMobileMenuOpen(false);
    setPreviewKey(k => k + 1);
  };

  const handleGenerate = async (isRefinement = false) => {
    const activePrompt = isRefinement ? refinePrompt : prompt;
    if (!activePrompt.trim() || (!isRefinement && !projectTitle.trim())) return;

    setIsGenerating(true);
    setError(null);

    const controller = new AbortController();
    abortControllerRef.current = controller;

    try {
      const result = await generateAppCode(activePrompt, selectedModel, isRefinement ? code : undefined, controller.signal);
      const newProjectId = Date.now().toString();
      const newProject: GeneratedProject = {
        id: newProjectId,
        name: isRefinement ? `Refined: ${activePrompt.substring(0, 20)}...` : projectTitle.trim(),
        prompt: activePrompt,
        code: result.code,
        timestamp: Date.now(),
        parentId: isRefinement ? (activeProjectId || undefined) : undefined
      };

      setCode(result.code);
      setEditableCode(result.code);
      setActiveProjectId(newProjectId);
      saveProjectLocally(newProject);
      if (isRefinement) setRefinePrompt('');
      setViewMode('preview');
      setPreviewKey(k => k + 1);
    } catch (err: any) {
      setError(err.message || "Generation failed.");
    } finally {
      setIsGenerating(false);
      abortControllerRef.current = null;
    }
  };

  const loadFromHistory = (project: GeneratedProject) => {
    setProjectTitle(project.name);
    setPrompt(project.prompt);
    setCode(project.code);
    setEditableCode(project.code);
    setActiveProjectId(project.id);
    setViewMode('preview');
    setIsMobileMenuOpen(false);
    setPreviewKey(k => k + 1);
  };

  const applyManualChanges = () => {
    setCode(editableCode);
    setPreviewKey(k => k + 1);
    const current = history.find(p => p.id === activeProjectId);
    if (current) {
      const updatedProject = { ...current, code: editableCode, timestamp: Date.now() };
      saveProjectLocally(updatedProject);
    }
    setApplySuccess(true);
    setTimeout(() => setApplySuccess(false), 2000);
  };

  const rootProjects = history.filter(p => !p.parentId && p.name.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="flex h-screen bg-gray-50 text-gray-900 font-sans selection:bg-blue-100 overflow-hidden">
      <aside className={`fixed md:static inset-y-0 left-0 w-72 md:w-64 border-r border-gray-200 flex flex-col bg-white shrink-0 z-50 transition-transform duration-300 md:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-5 border-b border-gray-100 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-1.5 rounded-lg shadow-sm"><Sparkles className="text-white w-4 h-4" /></div>
            <span className="font-bold text-sm tracking-tight uppercase text-gray-600">AI Studio</span>
          </div>
          <button onClick={() => setIsMobileMenuOpen(false)} className="md:hidden p-2 text-gray-400"><X size={20} /></button>
        </div>
        <div className="p-4 space-y-3">
          <div className="grid grid-cols-2 gap-2">
            <button onClick={() => { setProjectTitle(''); setPrompt(''); setCode(''); setViewMode('build'); setActiveProjectId(null); }} className="flex flex-col items-center justify-center gap-1.5 bg-gray-900 text-white p-3 rounded-xl transition-all text-[10px] font-bold uppercase hover:bg-black transition-colors"><Plus size={16} /> New</button>
            <button onClick={handleCreateBlankProject} className="flex flex-col items-center justify-center gap-1.5 bg-blue-50 text-blue-600 border border-blue-100 p-3 rounded-xl transition-all text-[10px] font-bold uppercase hover:bg-blue-100 transition-colors"><Cpu size={16} /> Blank</button>
          </div>
          <div className="relative group">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
            <input type="text" placeholder="Search projects..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-xl text-xs focus:outline-none focus:ring-2 focus:ring-blue-500/20" />
          </div>
        </div>
        <div className="flex-1 overflow-y-auto px-3 py-2">
          {rootProjects.length === 0 ? (
            <div className="text-center py-10 px-4">
              <p className="text-[10px] text-gray-400 font-medium italic">No projects saved yet.</p>
            </div>
          ) : (
            rootProjects.map((project) => (
              <div key={project.id} onClick={() => loadFromHistory(project)} className={`group relative px-3 py-2.5 rounded-lg cursor-pointer flex flex-col transition-all border border-transparent mb-1 ${activeProjectId === project.id ? 'bg-blue-50 border-blue-100' : 'hover:bg-gray-100'}`}>
                <span className={`text-xs font-bold truncate ${activeProjectId === project.id ? 'text-blue-700' : 'text-gray-700'}`}>{project.name}</span>
                <span className="text-[9px] text-gray-400 mt-0.5">{new Date(project.timestamp).toLocaleDateString()}</span>
              </div>
            ))
          )}
        </div>
      </aside>

      <main className="flex-1 flex flex-col relative overflow-hidden h-full">
        <header className="h-14 border-b border-gray-200 flex items-center justify-between px-6 bg-white z-20 shrink-0">
          <div className="flex items-center gap-6">
            <button onClick={() => setIsMobileMenuOpen(true)} className="md:hidden p-2 text-gray-600"><Menu size={20} /></button>
            <nav className="flex items-center gap-1 bg-gray-100/80 p-1 rounded-xl">
              {['build', 'preview', 'code'].map((tab) => (
                <button key={tab} onClick={() => setViewMode(tab as ViewMode)} className={`px-4 py-1 rounded-lg text-xs font-bold transition-all ${viewMode === tab ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>{tab.charAt(0).toUpperCase() + tab.slice(1)}</button>
              ))}
            </nav>
          </div>
        </header>

        <div className="flex-1 relative overflow-hidden">
          {viewMode === 'build' && (
            <div className="h-full overflow-y-auto bg-white flex flex-col items-center justify-center p-8 max-w-4xl mx-auto w-full">
              <div className="text-center mb-10">
                <div className="inline-flex p-4 rounded-3xl bg-blue-50 text-blue-600 mb-6"><Sparkles size={32} /></div>
                <h2 className="text-4xl font-extrabold text-gray-900 mb-4 tracking-tight">AI App Studio</h2>
                <p className="text-gray-500 text-lg">Generate functional web applications from simple prompts.</p>
              </div>
              <div className="w-full space-y-6 max-w-2xl">
                <input type="text" value={projectTitle} onChange={(e) => setProjectTitle(e.target.value)} placeholder="Project Name" className="w-full px-6 py-4 bg-gray-50 border-2 border-gray-100 focus:border-blue-500 focus:bg-white rounded-2xl text-gray-800 focus:outline-none transition-all text-lg shadow-inner" />
                <textarea value={prompt} onChange={(e) => setPrompt(e.target.value)} placeholder="Describe your app..." className="w-full h-40 p-6 bg-gray-50 border-2 border-gray-100 focus:border-blue-500 focus:bg-white rounded-3xl resize-none text-gray-800 focus:outline-none transition-all text-lg shadow-inner" />
                {!isGenerating ? (
                  <button disabled={!prompt.trim() || !projectTitle.trim()} onClick={() => handleGenerate(false)} className="w-full py-5 bg-gray-900 hover:bg-black disabled:bg-gray-200 text-white rounded-2xl font-bold text-lg shadow-lg transition-all flex items-center justify-center gap-3 active:scale-[0.98]">Launch Build <ArrowRight size={18} /></button>
                ) : (
                  <div className="w-full py-5 bg-blue-50 text-blue-600 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 animate-pulse">
                    <Loader2 className="animate-spin" /> Generating...
                  </div>
                )}
                {error && <div className="p-4 bg-red-50 border border-red-100 text-red-600 rounded-xl text-sm font-medium">{error}</div>}
              </div>
            </div>
          )}

          {viewMode === 'preview' && (
            <div className="h-full w-full relative">
              <PreviewFrame code={code} device={device} orientation={orientation} key={previewKey} />
              {/* Optional Refinement Bar */}
              <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-full max-w-xl px-4">
                <div className="bg-white/90 backdrop-blur-md border border-gray-200 rounded-2xl shadow-xl p-2 flex items-center gap-2">
                  <input 
                    type="text" 
                    value={refinePrompt} 
                    onChange={(e) => setRefinePrompt(e.target.value)} 
                    placeholder="Refine this app..." 
                    className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-4 h-10"
                    onKeyDown={(e) => e.key === 'Enter' && handleGenerate(true)}
                  />
                  <button 
                    onClick={() => handleGenerate(true)} 
                    disabled={isGenerating || !refinePrompt.trim()} 
                    className="bg-blue-600 hover:bg-blue-700 disabled:bg-gray-200 text-white p-2 rounded-xl transition-colors"
                  >
                    {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <CornerDownRight size={18} />}
                  </button>
                </div>
              </div>
            </div>
          )}

          {viewMode === 'code' && (
            <div className="h-full w-full bg-[#0d1117] flex flex-col">
              <div className="flex items-center justify-between px-4 py-3 border-b border-gray-800 bg-[#0d1117]">
                <span className="text-[10px] font-mono text-gray-500 uppercase">Source</span>
                <div className="flex items-center gap-4">
                  <button onClick={applyManualChanges} className={`text-[10px] font-bold flex items-center gap-1.5 transition-all ${applySuccess ? 'text-green-400' : 'text-blue-400'}`}>{applySuccess ? <Check size={12} /> : <Save size={12} />} Apply</button>
                  <button onClick={() => { navigator.clipboard.writeText(editableCode); setCopied(true); setTimeout(() => setCopied(false), 2000); }} className="text-[10px] font-bold text-gray-400 hover:text-white flex items-center gap-1.5">{copied ? <Check size={12} /> : <Copy size={12} />} Copy</button>
                </div>
              </div>
              <textarea value={editableCode} onChange={(e) => setEditableCode(e.target.value)} className="w-full flex-1 p-6 bg-[#0d1117] text-gray-300 font-mono text-sm leading-relaxed resize-none focus:outline-none" spellCheck={false} />
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

// Firebase integration has been removed. 
