          <div className="flex items-center gap-6">
            <button onClick={() => setIsMobileMenuOpen(true)} className="md:hidden p-2 text-gray-600"><Menu size={20} /></button>
            <nav className="flex items-center gap-1 bg-gray-50 p-1 rounded-xl">
              {['build', 'preview', 'code'].map((tab) => (
                <button 
                  key={tab} 
                  onClick={() => setViewMode(tab as ViewMode)} 
                  className={`px-5 py-1.5 rounded-lg text-xs font-bold transition-all ${viewMode === tab ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
                >
                  {tab.charAt(0).toUpperCase() + tab.slice(1)}
                </button>
              ))}
            </nav>
          </div>

          {viewMode === 'preview' && (
            <div className="flex items-center gap-1 bg-gray-50 p-1 rounded-xl">
              {[
                { id: PreviewDevice.DESKTOP, icon: Monitor },
                { id: PreviewDevice.TABLET, icon: Tablet },
                { id: PreviewDevice.MOBILE, icon: Smartphone }
              ].map((d) => (
                <button 
                  key={d.id}
                  onClick={() => setDevice(d.id)}
                  className={`p-2 rounded-lg transition-all ${device === d.id ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
                >
                  <d.icon size={16} />
                </button>
              ))}
            </div>
          )}
        </header>

        <div className="flex-1 relative overflow-hidden">
          {viewMode === 'build' && (
            <div className="h-full overflow-y-auto bg-white flex flex-col items-center justify-center p-8 max-w-4xl mx-auto w-full">
              <div className="text-center mb-10">
                <div className="inline-flex p-5 rounded-[2rem] bg-indigo-50 text-indigo-600 mb-6 animate-in zoom-in duration-500 shadow-2xl shadow-indigo-100"><Sparkles size={40} /></div>
                <h2 className="text-4xl font-extrabold text-gray-900 mb-4 tracking-tight">Create your next app.</h2>
                <p className="text-gray-500 text-lg max-w-md mx-auto">Describe the functionality, styling, and features. Our AI will handle the architecture.</p>
              </div>
              <div className="w-full space-y-6 max-w-2xl animate-in slide-in-from-bottom-4 duration-700">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Project Identifier</label>
                  <input 
                    type="text" 
                    value={projectTitle} 
                    onChange={(e) => setProjectTitle(e.target.value)} 
                    placeholder="e.g., Portfolio Dashboard" 
                    className="w-full px-6 py-4 bg-gray-50 border-2 border-transparent focus:border-indigo-500 focus:bg-white rounded-2xl text-gray-800 focus:outline-none transition-all text-lg shadow-sm" 
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Concept Prompt</label>
                  <textarea 
                    value={prompt} 
                    onChange={(e) => setPrompt(e.target.value)} 
                    placeholder="Describe a responsive dashboard with a dark theme and real-time charts..." 
                    className="w-full h-40 p-6 bg-gray-50 border-2 border-transparent focus:border-indigo-500 focus:bg-white rounded-[2rem] resize-none text-gray-800 focus:outline-none transition-all text-lg shadow-sm" 
                  />
                </div>
                {!isGenerating ? (
                  <button 
                    disabled={!prompt.trim() || !projectTitle.trim()} 
                    onClick={() => handleGenerate(false)} 
                    className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 disabled:bg-gray-200 text-white rounded-[2rem] font-bold text-xl shadow-xl shadow-indigo-200 transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
                  >
                    Build Application <ArrowRight size={20} />
                  </button>
                ) : (
                  <div className="w-full py-5 bg-indigo-50 text-indigo-600 rounded-[2rem] font-bold text-xl flex items-center justify-center gap-3 animate-pulse border-2 border-indigo-100">
                    <Loader2 className="animate-spin" /> Architecting...
                  </div>
                )}
                {error && <div className="p-4 bg-red-50 border border-red-100 text-red-600 rounded-2xl text-sm font-medium flex items-center gap-2"><Info size={16}/> {error}</div>}
              </div>
            </div>
          )}

          {viewMode === 'preview' && (
            <div className="h-full w-full relative group">
              <PreviewFrame code={code} device={device} orientation={orientation} key={previewKey} />

              {/* Refinement Overlay */}
              <div className="absolute bottom-8 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 transition-transform group-hover:translate-y-0 translate-y-2 opacity-0 group-hover:opacity-100 duration-300">
                <div className="glass border border-white/40 rounded-[2rem] shadow-2xl p-2 flex items-center gap-2">
                  <div className="pl-4 text-indigo-500"><MessageSquare size={18}/></div>
                  <input 
                    type="text" 
                    value={refinePrompt} 
                    onChange={(e) => setRefinePrompt(e.target.value)} 
                    placeholder="Add a sidebar, change colors, or add a feature..." 
                    className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-2 h-10 placeholder:text-gray-400"
                    onKeyDown={(e) => e.key === 'Enter' && handleGenerate(true)}
                  />
                  <button 
                    onClick={() => handleGenerate(true)} 
                    disabled={isGenerating || !refinePrompt.trim()} 
                    className="bg-indigo-600 hover:bg-indigo-700 disabled:bg-gray-200 text-white p-3 rounded-full transition-all shadow-lg shadow-indigo-200"
                  >
                    {isGenerating ? <Loader2 size={20} className="animate-spin" /> : <CornerDownRight size={20} />}
                  </button>
                </div>
              </div>
            </div>
          )}

          {viewMode === 'code' && (
            <div className="h-full w-full bg-[#0d1117] flex flex-col">
              <div className="flex items-center justify-between px-6 py-4 border-b border-gray-800 bg-[#0d1117]">
                <div className="flex items-center gap-3">
                  <div className="w-3 h-3 rounded-full bg-red-500/20 border border-red-500/50"></div>
                  <div className="w-3 h-3 rounded-full bg-yellow-500/20 border border-yellow-500/50"></div>
                  <div className="w-3 h-3 rounded-full bg-green-500/20 border border-green-500/50"></div>
                  <span className="text-[10px] font-mono text-gray-500 uppercase tracking-widest ml-4">index.html</span>
                </div>
                <div className="flex items-center gap-6">
                  <button onClick={applyManualChanges} className={`text-[11px] font-bold flex items-center gap-2 transition-all px-3 py-1.5 rounded-lg ${applySuccess ? 'bg-green-500/10 text-green-400' : 'bg-indigo-500/10 text-indigo-400 hover:bg-indigo-500/20'}`}>{applySuccess ? <Check size={14} /> : <Save size={14} />} Apply Changes</button>
                  <button onClick={() => { navigator.clipboard.writeText(editableCode); setCopied(true); setTimeout(() => setCopied(false), 2000); }} className="text-[11px] font-bold text-gray-400 hover:text-white flex items-center gap-2 transition-colors">{copied ? <Check size={14} /> : <Copy size={14} />} Copy Code</button>
                </div>
              </div>
              <textarea 
                value={editableCode} 
                onChange={(e) => setEditableCode(e.target.value)} 
                className="w-full flex-1 p-8 bg-[#0d1117] text-gray-300 font-mono text-sm leading-relaxed resize-none focus:outline-none" 
                spellCheck={false} 
              />
            </div>
          )}
        </div>
      </main>

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in-95 duration-200">
            <div className="p-8 border-b border-gray-50 flex items-center justify-between">
              <h3 className="font-bold text-xl">Studio Settings</h3>
              <button onClick={() => setShowSettings(false)} className="text-gray-400 hover:text-gray-900 transition-colors"><X/></button>
            </div>
            <div className="p-8 space-y-8">
              <div className="space-y-3">
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">AI Model Engine</label>
                <div className="grid grid-cols-1 gap-3">
                  {[
                    { id: 'gemini-3-flash-preview', name: 'Gemini 3 Flash', desc: 'Fastest generation, great for simple apps.' },
                    { id: 'gemini-3-pro-preview', name: 'Gemini 3 Pro', desc: 'Superior reasoning for complex architectures.' }
                  ].map(m => (
                    <button 
                      key={m.id}
                      onClick={() => setSelectedModel(m.id)}
                      className={`text-left p-4 rounded-2xl border-2 transition-all ${selectedModel === m.id ? 'border-indigo-600 bg-indigo-50/50' : 'border-gray-100 hover:border-gray-200 hover:bg-gray-50'}`}
                    >
                      <div className="flex items-center justify-between mb-1">
                        <span className="font-bold text-sm">{m.name}</span>
                        {selectedModel === m.id && <Check size={16} className="text-indigo-600" />}
                      </div>
                      <p className="text-[10px] text-gray-500 leading-relaxed">{m.desc}</p>
                    </button>
                  ))}
                </div>
              </div>
            </div>
            <div className="p-8 pt-0">
              <button onClick={() => setShowSettings(false)} className="w-full py-4 bg-gray-900 text-white rounded-2xl font-bold transition-all hover:bg-black">Save Preferences</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Plus, Settings, Sparkles, Copy, Check, X, 
  ArrowRight, Menu, Cpu, 
  Loader2, CornerDownRight, 
  Search, Pencil, Trash2, Save, Monitor, Tablet, Smartphone, Info,
  MessageSquare
} from 'lucide-react';
import { PreviewDevice, GeneratedProject, ViewMode, Orientation } from './types.ts';
import { generateAppCode } from './services/geminiService.ts';
import PreviewFrame from './components/PreviewFrame.tsx';

const STORAGE_KEY = 'ai_studio_projects';

const App: React.FC = () => {
  const [projectTitle, setProjectTitle] = useState('');
  const [prompt, setPrompt] = useState('');
  const [refinePrompt, setRefinePrompt] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [code, setCode] = useState('');
  const [editableCode, setEditableCode] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [viewMode, setViewMode] = useState<ViewMode>('build');
  const [device, setDevice] = useState<PreviewDevice>(PreviewDevice.DESKTOP);
  const [orientation, setOrientation] = useState<Orientation>('portrait');
  const [history, setHistory] = useState<GeneratedProject[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });
  const [copied, setCopied] = useState(false);
  const [applySuccess, setApplySuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeProjectId, setActiveProjectId] = useState<string | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [selectedModel, setSelectedModel] = useState('gemini-3-flash-preview');
  const [previewKey, setPreviewKey] = useState(0);

  // Renaming state
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');

  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(history));
  }, [history]);

  const saveProjectLocally = (project: GeneratedProject) => {
    setHistory(prev => {
      const index = prev.findIndex(p => p.id === project.id);
      if (index !== -1) {
        const next = [...prev];
        next[index] = project;
        return next;
      }
      return [project, ...prev];
    });
  };

  const handleDeleteProject = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('Are you sure you want to delete this project?')) {
      setHistory(prev => prev.filter(p => p.id !== id));
      if (activeProjectId === id) {
        setActiveProjectId(null);
        setCode('');
        setEditableCode('');
        setViewMode('build');
      }
    }
  };

  const startRenaming = (e: React.MouseEvent, project: GeneratedProject) => {
    e.stopPropagation();
    setEditingId(project.id);
    setEditValue(project.name);
  };

  const finishRenaming = (id: string) => {
    if (editValue.trim()) {
      setHistory(prev => prev.map(p => p.id === id ? { ...p, name: editValue.trim() } : p));
    }
    setEditingId(null);
  };

  const handleCreateBlankProject = () => {
    const blankBoilerplate = `<!DOCTYPE html>\n<html lang="en">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>Blank Project</title>\n    <script src="https://cdn.tailwindcss.com"></script>\n</head>\n<body class="bg-white min-h-screen flex items-center justify-center font-sans text-gray-300 italic">\n    Empty Canvas\n</body>\n</html>`;
    const newProjectId = Date.now().toString();
    const newProject: GeneratedProject = { 
      id: newProjectId, 
      name: "Untitled Canvas", 
      prompt: "Blank template", 
      code: blankBoilerplate, 
      timestamp: Date.now() 
    };
    setProjectTitle("Untitled Canvas");
    setPrompt("");
    setCode(blankBoilerplate);
    setEditableCode(blankBoilerplate);
    setActiveProjectId(newProjectId);
    saveProjectLocally(newProject);
    setViewMode('preview');
    setIsMobileMenuOpen(false);
    setPreviewKey(k => k + 1);
  };

  const handleGenerate = async (isRefinement = false) => {
    const activePrompt = isRefinement ? refinePrompt : prompt;
    if (!activePrompt.trim() || (!isRefinement && !projectTitle.trim())) return;

    setIsGenerating(true);
    setError(null);

    const controller = new AbortController();
    abortControllerRef.current = controller;

    try {
      const result = await generateAppCode(activePrompt, selectedModel, isRefinement ? code : undefined, controller.signal);
      const newProjectId = Date.now().toString();
      const newProject: GeneratedProject = {
        id: newProjectId,
        name: isRefinement ? `Refined: ${activePrompt.substring(0, 20)}...` : projectTitle.trim(),
        prompt: activePrompt,
        code: result.code,
        timestamp: Date.now(),
        parentId: isRefinement ? (activeProjectId || undefined) : undefined
      };

      setCode(result.code);
      setEditableCode(result.code);
      setActiveProjectId(newProjectId);
      saveProjectLocally(newProject);
      if (isRefinement) setRefinePrompt('');
      setViewMode('preview');
      setPreviewKey(k => k + 1);
    } catch (err: any) {
      setError(err.message || "Generation failed.");
    } finally {
      setIsGenerating(false);
      abortControllerRef.current = null;
    }
  };

  const loadFromHistory = (project: GeneratedProject) => {
    setProjectTitle(project.name);
    setPrompt(project.prompt);
    setCode(project.code);
    setEditableCode(project.code);
    setActiveProjectId(project.id);
    setViewMode('preview');
    setIsMobileMenuOpen(false);
    setPreviewKey(k => k + 1);
  };

  const applyManualChanges = () => {
    setCode(editableCode);
    setPreviewKey(k => k + 1);
    const current = history.find(p => p.id === activeProjectId);
    if (current) {
      const updatedProject = { ...current, code: editableCode, timestamp: Date.now() };
      saveProjectLocally(updatedProject);
    }
    setApplySuccess(true);
    setTimeout(() => setApplySuccess(false), 2000);
  };

  const filteredHistory = history.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="flex h-screen bg-white text-gray-900 font-sans selection:bg-blue-100 overflow-hidden">
      {/* Sidebar */}
      <aside className={`fixed md:static inset-y-0 left-0 w-72 md:w-64 border-r border-gray-100 flex flex-col bg-white shrink-0 z-50 transition-transform duration-300 md:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-6 border-b border-gray-50 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg shadow-lg shadow-indigo-200"><Sparkles className="text-white w-4 h-4" /></div>
            <span className="font-bold text-sm tracking-tight text-gray-800">App Studio</span>
          </div>
          <button onClick={() => setIsMobileMenuOpen(false)} className="md:hidden p-2 text-gray-400 hover:text-gray-600"><X size={20} /></button>
        </div>

        <div className="p-4 space-y-4">
          <div className="grid grid-cols-2 gap-2">
            <button onClick={() => { setProjectTitle(''); setPrompt(''); setCode(''); setViewMode('build'); setActiveProjectId(null); }} className="flex flex-col items-center justify-center gap-1.5 bg-gray-900 text-white p-3 rounded-xl hover:bg-black transition-all text-[10px] font-bold uppercase"><Plus size={16} /> New</button>
            <button onClick={handleCreateBlankProject} className="flex flex-col items-center justify-center gap-1.5 bg-gray-50 text-gray-600 border border-gray-200 p-3 rounded-xl hover:bg-gray-100 transition-all text-[10px] font-bold uppercase"><Cpu size={16} /> Blank</button>
          </div>

          <div className="relative">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
            <input 
              type="text" 
              placeholder="Search..." 
              value={searchTerm} 
              onChange={(e) => setSearchTerm(e.target.value)} 
              className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-transparent rounded-xl text-xs focus:outline-none focus:bg-white focus:ring-2 focus:ring-indigo-500/10 transition-all"
            />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-3 py-2 space-y-1">
          <p className="px-3 text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Projects</p>
          {filteredHistory.length === 0 ? (
            <div className="px-4 py-8 text-center">
              <p className="text-xs text-gray-400 italic">Empty workspace</p>
            </div>
          ) : (
            filteredHistory.map((project) => (
              <div 
                key={project.id} 
                onClick={() => loadFromHistory(project)} 
                className={`group relative px-3 py-2.5 rounded-xl cursor-pointer flex items-center justify-between transition-all border ${activeProjectId === project.id ? 'bg-indigo-50 border-indigo-100 text-indigo-700 shadow-sm' : 'border-transparent text-gray-600 hover:bg-gray-50'}`}
              >
                <div className="flex-1 min-w-0 mr-2">
                  {editingId === project.id ? (
                    <input 
                      autoFocus
                      className="bg-white border border-indigo-200 rounded px-1 w-full text-xs font-medium outline-none"
                      value={editValue}
                      onChange={(e) => setEditValue(e.target.value)}
                      onBlur={() => finishRenaming(project.id)}
                      onKeyDown={(e) => e.key === 'Enter' && finishRenaming(project.id)}
                      onClick={(e) => e.stopPropagation()}
                    />
                  ) : (
                    <p className="text-xs font-medium truncate leading-tight">{project.name}</p>
                  )}
                  <p className="text-[9px] opacity-60 mt-0.5">{new Date(project.timestamp).toLocaleDateString()}</p>
                </div>

                <div className={`flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity ${activeProjectId === project.id ? 'opacity-100' : ''}`}>
                  <button onClick={(e) => startRenaming(e, project)} className="p-1 hover:bg-gray-200 rounded transition-colors"><Pencil size={12} /></button>
                  <button onClick={(e) => handleDeleteProject(e, project.id)} className="p-1 hover:bg-red-100 hover:text-red-500 rounded transition-colors"><Trash2 size={12} /></button>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-4 border-t border-gray-50">
          <button 
            onClick={() => setShowSettings(true)}
            className="w-full flex items-center gap-3 px-3 py-2 text-gray-500 hover:text-gray-900 hover:bg-gray-50 rounded-xl transition-all text-xs font-medium"
          >
            <Settings size={16} /> Settings
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col relative overflow-hidden h-full bg-white">
        <header className="h-16 border-b border-gray-50 flex items-center justify-between px-6 bg-white/80 backdrop-blur-md z-20 shrink-0">
          <div className="flex items-center gap-6">
            <button onClick={() => setIsMobileMenuOpen(true)} className="md:hidden p-2 text-gray-600"><Menu size={20} /></button>
            <nav className="flex items-center gap-1 bg-gray-50 p-1 rounded-xl">
              {['build', 'preview', 'code'].map((tab) => (
                <button 
                  key={tab} 
                  onClick={() => setViewMode(tab as ViewMode)} 
                  className={`px-5 py-1.5 rounded-lg text-xs font-bold transition-all ${viewMode === tab ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
                >
                  {tab.charAt(0).toUpperCase() + tab.slice(1)}
                </button>
              ))}
            </nav>
          </div>

          {viewMode === 'preview' && (
            <div className="flex items-center gap-1 bg-gray-50 p-1 rounded-xl">
              {[
                { id: PreviewDevice.DESKTOP, icon: Monitor },
                { id: PreviewDevice.TABLET, icon: Tablet },
                { id: PreviewDevice.MOBILE, icon: Smartphone }
              ].map((d) => (
                <button 
                  key={d.id}
                  onClick={() => setDevice(d.id)}
                  className={`p-2 rounded-lg transition-all ${device === d.id ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
                >
                  <d.icon size={16} />
                </button>
              ))}
            </div>
          )}
        </header>

        <div className="flex-1 relative overflow-hidden">
          {viewMode === 'build' && (
            <div className="h-full overflow-y-auto bg-white flex flex-col items-center justify-center p-8 max-w-4xl mx-auto w-full">
              <div className="text-center mb-10">
                <div className="inline-flex p-5 rounded-[2rem] bg-indigo-50 text-indigo-600 mb-6 animate-in zoom-in duration-500 shadow-2xl shadow-indigo-100"><Sparkles size={40} /></div>
                <h2 className="text-4xl font-extrabold text-gray-900 mb-4 tracking-tight">Create your next app.</h2>
                <p className="text-gray-500 text-lg max-w-md mx-auto">Describe the functionality, styling, and features. Our AI will handle the architecture.</p>
              </div>
              <div className="w-full space-y-6 max-w-2xl animate-in slide-in-from-bottom-4 duration-700">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Project Identifier</label>
                  <input 
                    type="text" 
                    value={projectTitle} 
                    onChange={(e) => setProjectTitle(e.target.value)} 
                    placeholder="e.g., Portfolio Dashboard" 
                    className="w-full px-6 py-4 bg-gray-50 border-2 border-transparent focus:border-indigo-500 focus:bg-white rounded-2xl text-gray-800 focus:outline-none transition-all text-lg shadow-sm" 
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Concept Prompt</label>
                  <textarea 
                    value={prompt} 
                    onChange={(e) => setPrompt(e.target.value)} 
                    placeholder="Describe a responsive dashboard with a dark theme and real-time charts..." 
                    className="w-full h-40 p-6 bg-gray-50 border-2 border-transparent focus:border-indigo-500 focus:bg-white rounded-[2rem] resize-none text-gray-800 focus:outline-none transition-all text-lg shadow-sm" 
                  />
                </div>
                {!isGenerating ? (
                  <button 
                    disabled={!prompt.trim() || !projectTitle.trim()} 
                    onClick={() => handleGenerate(false)} 
                    className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 disabled:bg-gray-200 text-white rounded-[2rem] font-bold text-xl shadow-xl shadow-indigo-200 transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
                  >
                    Build Application <ArrowRight size={20} />
                  </button>
                ) : (
                  <div className="w-full py-5 bg-indigo-50 text-indigo-600 rounded-[2rem] font-bold text-xl flex items-center justify-center gap-3 animate-pulse border-2 border-indigo-100">
                    <Loader2 className="animate-spin" /> Architecting...
                  </div>
                )}
                {error && <div className="p-4 bg-red-50 border border-red-100 text-red-600 rounded-2xl text-sm font-medium flex items-center gap-2"><Info size={16}/> {error}</div>}
              </div>
            </div>
          )}

          {viewMode === 'preview' && (
            <div className="h-full w-full relative group">
              <PreviewFrame code={code} device={device} orientation={orientation} key={previewKey} />

              {/* Refinement Overlay */}
              <div className="absolute bottom-8 left-1/2 -translate-x-1/2 w-full max-w-xl px-4 transition-transform group-hover:translate-y-0 translate-y-2 opacity-0 group-hover:opacity-100 duration-300">
                <div className="glass border border-white/40 rounded-[2rem] shadow-2xl p-2 flex items-center gap-2">
                  <div className="pl-4 text-indigo-500"><MessageSquare size={18}/></div>
                  <input 
                    type="text" 
                    value={refinePrompt} 
                    onChange={(e) => setRefinePrompt(e.target.value)} 
                    placeholder="Add a sidebar, change colors, or add a feature..." 
                    className="flex-1 bg-transparent border-none focus:ring-0 text-sm px-2 h-10 placeholder:text-gray-400"
                    onKeyDown={(e) => e.key === 'Enter' && handleGenerate(true)}
                  />
                  <button 
                    onClick={() => handleGenerate(true)} 
                    disabled={isGenerating || !refinePrompt.trim()} 
                    className="bg-indigo-600 hover:bg-indigo-700 disabled:bg-gray-200 text-white p-3 rounded-full transition-all shadow-lg shadow-indigo-200"
                  >
                    {isGenerating ? <Loader2 size={20} className="animate-spin" /> : <CornerDownRight size={20} />}
                  </button>
                </div>
              </div>
            </div>
          )}

          {viewMode === 'code' && (
            <div className="h-full w-full bg-[#0d1117] flex flex-col">
              <div className="flex items-center justify-between px-6 py-4 border-b border-gray-800 bg-[#0d1117]">
                <div className="flex items-center gap-3">
                  <div className="w-3 h-3 rounded-full bg-red-500/20 border border-red-500/50"></div>
                  <div className="w-3 h-3 rounded-full bg-yellow-500/20 border border-yellow-500/50"></div>
                  <div className="w-3 h-3 rounded-full bg-green-500/20 border border-green-500/50"></div>
                  <span className="text-[10px] font-mono text-gray-500 uppercase tracking-widest ml-4">index.html</span>
                </div>
                <div className="flex items-center gap-6">
                  <button onClick={applyManualChanges} className={`text-[11px] font-bold flex items-center gap-2 transition-all px-3 py-1.5 rounded-lg ${applySuccess ? 'bg-green-500/10 text-green-400' : 'bg-indigo-500/10 text-indigo-400 hover:bg-indigo-500/20'}`}>{applySuccess ? <Check size={14} /> : <Save size={14} />} Apply Changes</button>
                  <button onClick={() => { navigator.clipboard.writeText(editableCode); setCopied(true); setTimeout(() => setCopied(false), 2000); }} className="text-[11px] font-bold text-gray-400 hover:text-white flex items-center gap-2 transition-colors">{copied ? <Check size={14} /> : <Copy size={14} />} Copy Code</button>
                </div>
              </div>
              <textarea 
                value={editableCode} 
                onChange={(e) => setEditableCode(e.target.value)} 
                className="w-full flex-1 p-8 bg-[#0d1117] text-gray-300 font-mono text-sm leading-relaxed resize-none focus:outline-none" 
                spellCheck={false} 
              />
            </div>
          )}
        </div>
      </main>

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in-95 duration-200">
            <div className="p-8 border-b border-gray-50 flex items-center justify-between">
              <h3 className="font-bold text-xl">Studio Settings</h3>
              <button onClick={() => setShowSettings(false)} className="text-gray-400 hover:text-gray-900 transition-colors"><X/></button>
            </div>
            <div className="p-8 space-y-8">
              <div className="space-y-3">
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">AI Model Engine</label>
                <div className="grid grid-cols-1 gap-3">
                  {[
                    { id: 'gemini-3-flash-preview', name: 'Gemini 3 Flash', desc: 'Fastest generation, great for simple apps.' },
                    { id: 'gemini-3-pro-preview', name: 'Gemini 3 Pro', desc: 'Superior reasoning for complex architectures.' }
                  ].map(m => (
                    <button 
                      key={m.id}
                      onClick={() => setSelectedModel(m.id)}
                      className={`text-left p-4 rounded-2xl border-2 transition-all ${selectedModel === m.id ? 'border-indigo-600 bg-indigo-50/50' : 'border-gray-100 hover:border-gray-200 hover:bg-gray-50'}`}
                    >
                      <div className="flex items-center justify-between mb-1">
                        <span className="font-bold text-sm">{m.name}</span>
                        {selectedModel === m.id && <Check size={16} className="text-indigo-600" />}
                      </div>
                      <p className="text-[10px] text-gray-500 leading-relaxed">{m.desc}</p>
                    </button>
                  ))}
                </div>
              </div>
            </div>
            <div className="p-8 pt-0">
              <button onClick={() => setShowSettings(false)} className="w-full py-4 bg-gray-900 text-white rounded-2xl font-bold transition-all hover:bg-black">Save Preferences</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export interface GeneratedProject {
  id: string;
  name: string;
  prompt: string;
  code: string;
  timestamp: number;
  parentId?: string; // Menyimpan ID projek asal jika ini adalah refinement
}

export enum PreviewDevice {
  DESKTOP = 'desktop',
  MOBILE = 'mobile'
}

export type Orientation = 'portrait' | 'landscape';

export type ViewMode = 'build' | 'preview' | 'code';

// Fixed corrupted imports and removed duplicate type definitions from the top of the file
import React, { useState, useEffect, useRef } from 'react';
import { 
  Monitor, 
  Smartphone, 
  Plus, 
  Settings, 
  Sparkles, 
  Copy, 
  Trash2, 
  Check, 
  X, 
  MessageSquare, 
  ArrowRight, 
  Layout, 
  Layers, 
  Zap, 
  Menu, 
  Cpu, 
  ZapOff, 
  User, 
  ChevronUp, 
  ExternalLink, 
  ShieldCheck, 
  BarChart3, 
  Info, 
  Loader2, 
  CornerDownRight, 
  Type, 
  Search, 
  AlertTriangle, 
  Pencil, 
  Activity, 
  Square, 
  BarChart,
  Save,
  RefreshCw,
  BellRing,
  FileCode,
  FileText,
  Clock,
  Image as ImageIcon,
  Upload,
  File,
  Music,
  Video,
  Link as LinkIcon,
  Maximize2,
  Code,
  Download,
  Keyboard,
  History
} from 'lucide-react';
import { PreviewDevice, GeneratedProject, ViewMode, Orientation } from './types';
import { generateAppCode } from './services/geminiService';
import PreviewFrame from './components/PreviewFrame';

interface EditElementData {
  tagName: string;
  textContent: string;
  fontSize: string;
  fontFamily: string;
  href?: string;
  src?: string;
  elementRef: HTMLElement;
  outerHTML: string;
  css: string;
  js: string;
}

const App: React.FC = () => {
  const [projectTitle, setProjectTitle] = useState('');
  const [prompt, setPrompt] = useState('');
  const [refinePrompt, setRefinePrompt] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [code, setCode] = useState('');
  const [editableCode, setEditableCode] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [viewMode, setViewMode] = useState<ViewMode>('build');
  const [device, setDevice] = useState<PreviewDevice>(PreviewDevice.DESKTOP);
  const [orientation, setOrientation] = useState<Orientation>('portrait');
  const [history, setHistory] = useState<GeneratedProject[]>([]);
  const [copied, setCopied] = useState(false);
  const [applySuccess, setApplySuccess] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [quotaExhausted, setQuotaExhausted] = useState(false);
  const [showRefineSidebar, setShowRefineSidebar] = useState(false);
  const [activeProjectId, setActiveProjectId] = useState<string | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [selectedModel, setSelectedModel] = useState('gemini-3-flash-preview');
  const [previewKey, setPreviewKey] = useState(0);
  const [submitKeyShortcut, setSubmitKeyShortcut] = useState<'ctrl-enter' | 'enter'>('ctrl-enter');
  const [isAutosaveEnabled, setIsAutosaveEnabled] = useState(true);
  const [lastAutosave, setLastAutosave] = useState<number | null>(null);

  // Realtime Edit State
  const [isRealtimeEditMode, setIsRealtimeEditMode] = useState(false);
  const [activeEditElement, setActiveEditElement] = useState<EditElementData | null>(null);

  // Generic File Upload State
  const [selectedFile, setSelectedFile] = useState<{ data: string, mimeType: string, name: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const refineFileInputRef = useRef<HTMLInputElement>(null);

  // Renaming state
  const [editingProjectId, setEditingProjectId] = useState<string | null>(null);
  const [renameValue, setRenameValue] = useState('');

  // Overwrite state
  const [overwriteCandidate, setOverwriteCandidate] = useState<GeneratedProject | null>(null);

  // Delete confirmation state
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [projectToDeleteId, setProjectToDeleteId] = useState<string | null>(null);

  // Abort Controller for stopping generation
  const abortControllerRef = useRef<AbortController | null>(null);

  const sidebarScrollRef = useRef<HTMLDivElement>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Load History
    const savedHistory = localStorage.getItem('ai_studio_history_v2');
    if (savedHistory) {
      try {
        const parsed = JSON.parse(savedHistory);
        setHistory(parsed);
      } catch (e) {
        console.error("Failed to parse history");
      }
    }

    // Load Model
    const savedModel = localStorage.getItem('ai_studio_selected_model');
    if (savedModel) {
      if (savedModel.startsWith('gpt')) {
        setSelectedModel('gemini-3-flash-preview');
      } else {
        setSelectedModel(savedModel);
      }
    }

    // Load Submit Shortcut
    const savedShortcut = localStorage.getItem('ai_studio_submit_shortcut');
    if (savedShortcut === 'ctrl-enter' || savedShortcut === 'enter') {
      setSubmitKeyShortcut(savedShortcut);
    }

    // Load Autosave Preference
    const savedAutosave = localStorage.getItem('ai_studio_autosave_enabled');
    if (savedAutosave !== null) {
      setIsAutosaveEnabled(savedAutosave === 'true');
    }

    return () => {
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, []);

  useEffect(() => {
    localStorage.setItem('ai_studio_history_v2', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('ai_studio_selected_model', selectedModel);
  }, [selectedModel]);

  useEffect(() => {
    localStorage.setItem('ai_studio_submit_shortcut', submitKeyShortcut);
  }, [submitKeyShortcut]);

  useEffect(() => {
    localStorage.setItem('ai_studio_autosave_enabled', isAutosaveEnabled.toString());
  }, [isAutosaveEnabled]);

  // Autosave logic
  useEffect(() => {
    if (!isAutosaveEnabled || !activeProjectId || isGenerating) return;

    const timeout = setTimeout(() => {
      setHistory(prev => {
        const project = prev.find(p => p.id === activeProjectId);
        if (!project) return prev;

        // Only update if something actually changed to prevent excessive writes
        if (project.code === code && project.name === projectTitle && project.prompt === prompt) {
          return prev;
        }

        const updatedHistory = prev.map(p => 
          p.id === activeProjectId 
            ? { ...p, code, name: projectTitle || p.name, prompt, timestamp: Date.now() } 
            : p
        );
        setLastAutosave(Date.now());
        return updatedHistory;
      });
    }, 10000); // Autosave after 10 seconds of no changes

    return () => clearTimeout(timeout);
  }, [code, projectTitle, prompt, activeProjectId, isAutosaveEnabled, isGenerating]);

  const handleStopGeneration = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    setIsGenerating(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = (reader.result as string).split(',')[1];
      setSelectedFile({
        data: base64String,
        mimeType: file.type,
        name: file.name
      });
    };
    reader.readAsDataURL(file);
    // Clear input so same file can be selected again
    e.target.value = '';
  };

  const triggerUpload = () => {
    fileInputRef.current?.click();
  };

  const triggerRefineUpload = () => {
    refineFileInputRef.current?.click();
  };

  const handleCreateBlankProject = () => {
    const blankBoilerplate = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Blank Project</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <style>
        body { background-color: #ffffff; min-height: 100vh; font-family: sans-serif; }
    </style>
</head>
<body>
    <div class="flex items-center justify-center min-h-screen">
        <p class="text-gray-400 font-medium italic">Empty Canvas</p>
    </div>
</body>
</html>`;

    const newProjectId = Date.now().toString();
    const newProject: GeneratedProject = {
      id: newProjectId,
      name: "Blank Project",
      prompt: "Started with a blank template",
      code: blankBoilerplate,
      timestamp: Date.now()
    };

    setProjectTitle("Blank Project");
    setPrompt("");
    setCode(blankBoilerplate);
    setEditableCode(blankBoilerplate);
    setHistory(prev => [newProject, ...prev]);
    setActiveProjectId(newProjectId);
    setViewMode('preview');
    setIsMobileMenuOpen(false);
    setPreviewKey(k => k + 1);
  };

  const saveToSimulatedFS = (title: string, appCode: string, appPrompt: string) => {
    const basePath = `Web Studio/${title.trim()}`;
    localStorage.setItem(`${basePath}/index.html`, appCode);
    localStorage.setItem(`${basePath}/metadata.json`, JSON.stringify({
      name: title.trim(),
      prompt: appPrompt,
      timestamp: Date.now()
    }));
  };

  const triggerFileDownload = (filename: string, content: string) => {
    const blob = new Blob([content], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${filename}.html`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleConfirmOverwrite = () => {
    if (!overwriteCandidate) return;
    setHistory(prev => prev.map(p => p.id === overwriteCandidate.id ? { ...p, code, prompt, timestamp: Date.now() } : p));
    setActiveProjectId(overwriteCandidate.id);
    saveToSimulatedFS(projectTitle, code, prompt);
    triggerFileDownload(projectTitle, code);
    setOverwriteCandidate(null);
    setSaveSuccess(true);
    setTimeout(() => setSaveSuccess(false), 2000);
  };

  const handleSaveProject = () => {
    if (!projectTitle.trim() || !code) return;
    const existingProject = history.find(p => p.name.toLowerCase() === projectTitle.toLowerCase() && !p.parentId);
    if (existingProject && existingProject.id !== activeProjectId) {
      setOverwriteCandidate(existingProject);
    } else if (activeProjectId) {
      setHistory(prev => prev.map(p => p.id === activeProjectId ? { ...p, name: projectTitle.trim(), code, prompt, timestamp: Date.now() } : p));
      saveToSimulatedFS(projectTitle, code, prompt);
      triggerFileDownload(projectTitle, code);
      setSaveSuccess(true);
      setTimeout(() => setSaveSuccess(false), 2000);
    } else {
      const newProjectId = Date.now().toString();
      const newProject: GeneratedProject = {
        id: newProjectId,
        name: projectTitle.trim(),
        prompt: prompt,
        code: code,
        timestamp: Date.now()
      };
      setHistory(prev => [newProject, ...prev]);
      setActiveProjectId(newProjectId);
      saveToSimulatedFS(projectTitle, code, prompt);
      triggerFileDownload(projectTitle, code);
      setSaveSuccess(true);
      setTimeout(() => setSaveSuccess(false), 2000);
    }
  };

  const handleGenerate = async (isRefinement = false) => {
    const activePrompt = isRefinement ? refinePrompt : prompt;
    if (!activePrompt.trim()) return;
    if (!isRefinement && !projectTitle.trim()) return;

    setIsGenerating(true);
    setError(null);
    setQuotaExhausted(false);

    if (isRefinement) {
      setShowRefineSidebar(false);
    } else if (window.innerWidth < 768) {
      setShowRefineSidebar(false);
    }

    const controller = new AbortController();
    abortControllerRef.current = controller;

    try {
      const result = await generateAppCode(
        activePrompt, 
        selectedModel, 
        isRefinement ? code : undefined,
        controller.signal,
        selectedFile || undefined
      );

      const currentActive = history.find(p => p.id === activeProjectId);
      const parentId = isRefinement ? (currentActive?.parentId || activeProjectId || undefined) : undefined;

      const newProjectId = Date.now().toString();
      const newProject: GeneratedProject = {
        id: newProjectId,
        name: isRefinement 
          ? `Refined: ${activePrompt.substring(0, 20)}...` 
          : projectTitle.trim(),
        prompt: activePrompt,
        code: result.code,
        timestamp: Date.now(),
        parentId: parentId
      };

      setCode(result.code);
      setEditableCode(result.code);
      setHistory(prev => [newProject, ...prev]);
      setActiveProjectId(newProjectId);

      if (isRefinement) {
        setRefinePrompt('');
      }

      setSelectedFile(null);
      setViewMode('preview');
      setPreviewKey(k => k + 1);
    } catch (err: any) {
      if (err.message === "Generation cancelled by user.") return;
      if (err.message === "QUOTA_EXHAUSTED") setQuotaExhausted(true);
      else setError(err.message || "Something went wrong during generation.");
    } finally {
      setIsGenerating(false);
      abortControllerRef.current = null;
    }
  };

  const loadFromHistory = (project: GeneratedProject) => {
    const rootTitle = project.parentId 
      ? history.find(p => p.id === project.parentId)?.name || project.name 
      : project.name;
    setProjectTitle(rootTitle);
    setPrompt(project.prompt);
    setCode(project.code);
    setEditableCode(project.code);
    setActiveProjectId(project.id);
    setViewMode('preview');
    setIsMobileMenuOpen(false);
    setPreviewKey(k => k + 1);
  };

  const handleRename = (id: string, newName: string) => {
    if (!newName.trim()) {
      setEditingProjectId(null);
      return;
    }
    setHistory(prev => prev.map(p => p.id === id ? { ...p, name: newName } : p));
    if (activeProjectId === id) setProjectTitle(newName);
    setEditingProjectId(null);
  };

  const openDeleteConfirmation = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setProjectToDeleteId(id);
    setIsDeleteModalOpen(true);
  };

  const confirmDelete = () => {
    if (!projectToDeleteId) return;
    const id = projectToDeleteId;
    setHistory(prev => prev.filter(p => p.id !== id && p.parentId !== id));
    if (activeProjectId === id) {
      setActiveProjectId(null);
      setCode('');
      setEditableCode('');
      setViewMode('build');
    }
    setIsDeleteModalOpen(false);
    setProjectToDeleteId(null);
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(editableCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const applyManualChanges = () => {
    setCode(editableCode);
    setPreviewKey(k => k + 1);
    if (activeProjectId) {
      setHistory(prev => prev.map(p => p.id === activeProjectId ? { ...p, code: editableCode } : p));
    }
    setApplySuccess(true);
    setTimeout(() => setApplySuccess(false), 2000);
  };

  const handleReloadPreview = () => setPreviewKey(k => k + 1);

  const toggleFullScreen = () => {
    if (!previewContainerRef.current) return;

    if (!document.fullscreenElement) {
      previewContainerRef.current.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  const getModelBadgeInfo = (modelId: string) => {
    const isPro = modelId.includes('pro');
    const isV3 = modelId.includes('gemini-3');
    return {
      label: isPro ? 'Pro' : 'Flash',
      version: isV3 ? 'v3' : 'v2.5',
      className: isPro 
        ? 'bg-purple-100 text-purple-600 border border-purple-200' 
        : 'bg-yellow-100 text-yellow-700 border border-yellow-200'
    };
  };

  const toggleRefineSidebar = () => {
    const nextState = !showRefineSidebar;
    setShowRefineSidebar(nextState);
    if (nextState) {
      if (viewMode === 'build' && code) setViewMode('preview');
    }
  };

  const getFileIcon = (mimeType: string) => {
    if (mimeType.startsWith('image/')) return <ImageIcon size={18} />;
    if (mimeType.startsWith('audio/')) return <Music size={18} />;
    if (mimeType.startsWith('video/')) return <Video size={18} />;
    if (mimeType.startsWith('text/')) return <FileText size={18} />;
    return <File size={18} />;
  };

  const renderFilePreview = (file: { data: string, mimeType: string, name: string }, size: 'large' | 'small' = 'large') => {
    const isImage = file.mimeType.startsWith('image/');
    const dim = size === 'large' ? 'w-16 h-16' : 'w-8 h-8';

    return (
      <div className={`relative ${dim} rounded-xl overflow-hidden border-2 border-blue-50 shadow-lg bg-white flex items-center justify-center`}>
        {isImage ? (
          <img src={`data:${file.mimeType};base64,${file.data}`} alt="Selected" className="w-full h-full object-cover" />
        ) : (
          <div className="text-blue-500">
            {getFileIcon(file.mimeType)}
          </div>
        )}
        <button onClick={() => setSelectedFile(null)} className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity">
          <X size={size === 'large' ? 14 : 10} className="text-white" />
        </button>
      </div>
    );
  };

  const handleElementClick = (data: EditElementData) => {
    if (isRealtimeEditMode) {
      setActiveEditElement(data);
    }
  };

  const handleSaveElementChanges = () => {
    if (!activeEditElement) return;

    const el = activeEditElement.elementRef;

    // Check if HTML was changed, if so replace entirely
    if (el.outerHTML !== activeEditElement.outerHTML) {
      el.outerHTML = activeEditElement.outerHTML;
    } else {
      // Update basic properties
      if (activeEditElement.tagName !== 'IMG') {
        el.textContent = activeEditElement.textContent;
      }

      el.style.fontSize = activeEditElement.fontSize;
      el.style.fontFamily = activeEditElement.fontFamily;

      if (activeEditElement.tagName === 'A' && activeEditElement.href) {
        (el as HTMLAnchorElement).href = activeEditElement.href;
      }

      if (activeEditElement.tagName === 'IMG' && activeEditElement.src) {
        (el as HTMLImageElement).src = activeEditElement.src;
      }
    }

    // Capture updated HTML from the iframe's context and update state
    const iframe = document.querySelector('iframe');
    if (iframe && iframe.contentDocument) {
      const doc = iframe.contentDocument;

      // Update Styles if edited
      const styleTags = Array.from(doc.querySelectorAll('style')).filter(s => s.id !== 'studio-edit-mode-styles');
      if (styleTags.length > 0) {
        styleTags[0].textContent = activeEditElement.css;
      }

      // Update Scripts if edited
      const scriptTags = Array.from(doc.querySelectorAll('script'));
      if (scriptTags.length > 0) {
        scriptTags[0].textContent = activeEditElement.js;
      }

      const editStyle = doc.getElementById('studio-edit-mode-styles');
      if (editStyle) editStyle.remove();

      const taggedElements = doc.querySelectorAll('[data-studio-edit-active]');
      taggedElements.forEach(elem => elem.removeAttribute('data-studio-edit-active'));

      const updatedHTML = '<!DOCTYPE html>\n' + doc.documentElement.outerHTML;
      setCode(updatedHTML);
      setEditableCode(updatedHTML);
      if (activeProjectId) {
        setHistory(prev => prev.map(p => p.id === activeProjectId ? { ...p, code: updatedHTML } : p));
      }
    }

    setActiveEditElement(null);
  };

  const filteredHistory = history.filter(project => project.name.toLowerCase().includes(searchTerm.toLowerCase()));
  const rootProjects = filteredHistory.filter(p => !p.parentId);
  const activeProject = history.find(h => h.id === activeProjectId);

