                  <label className="flex items-center gap-2 text-[10px] font-bold text-gray-400 uppercase tracking-widest ml-1">
                    <ImageIcon size={12} className="text-blue-500" /> Image Source URL
                  </label>
                  <input 
                    type="text" 
                    value={activeEditElement.src || ''}
