                  </button>
                </div>
                <div className="h-6 w-px bg-gray-200 dark:bg-gray-700"></div>
                <div className="flex gap-4">
                  <button className="flex items-center gap-2 text-sm font-medium text-gray-600 dark:text-gray-400 hover:text-blue-600 transition-colors">
                    <Code size={18} />
                    View Code
                  </button>
                  <button className="flex items-center gap-2 text-sm font-medium text-gray-600 dark:text-gray-400 hover:text-blue-600 transition-colors">
                    <History size={18} />
                    History
                  </button>
                </div>
              </div>
              <div className="flex gap-3">
                <button 
                  onClick={() => {
                    navigator.clipboard.writeText(code);
                    setCopied(true);
                    setTimeout(() => setCopied(false), 2000);
                  }}
                  className="bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2 transition-all"
                >
                  {copied ? <Check size={16} className="text-green-500" /> : <Copy size={16} />}
                  {copied ? 'Copied' : 'Copy'}
                </button>
                <button className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2 transition-all">
                  <Download size={16} />
                  Export
                </button>
              </div>
            </div>

            <div className="border-4 border-gray-100 dark:border-gray-800 rounded-[2.5rem] overflow-hidden shadow-2xl h-[700px] bg-white">
              <PreviewFrame 
                code={code} 
                device={device} 
                orientation={orientation} 
                isRealtimeEditMode={isRealtimeEditMode}
              />
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

